/**
 * Auth.gs — Authentication & Session
 * Login PIN sederhana untuk 1 admin
 */

var SESSION_DURATION_HOURS = 8; // Session valid 8 jam

/**
 * Cek PIN login
 * @param {string} pin - PIN yang diinput user
 * @return {object} { token, appName } atau error
 */
function checkPin_(pin) {
  if (!pin || pin === '') {
    throw new Error('PIN tidak boleh kosong');
  }
  
  var storedPin = getSetting('APP_PIN');
  
  if (!storedPin) {
    throw new Error('PIN belum dikonfigurasi di sheet SETTING');
  }
  
  if (String(pin) !== String(storedPin)) {
    throw new Error('PIN salah');
  }
  
  // Generate session token sederhana
  var token = generateSessionToken();
  
  return {
    token: token,
    appName: getSetting('APP_NAME') || 'Kaldik & Pokok Doa Terpadu',
    message: 'Login berhasil'
  };
}

/**
 * Logout (hanya formalitas — session client-side)
 */
function logout_() {
  return { message: 'Logout berhasil' };
}

/**
 * Generate session token
 * Format: base64 encoded JSON { ts, random }
 */
function generateSessionToken() {
  var payload = {
    ts: new Date().getTime(),
    rnd: Math.random().toString(36).substring(2, 15)
  };
  return Utilities.base64Encode(JSON.stringify(payload));
}

/**
 * Validate session token (untuk cek di backend jika diperlukan)
 */
function validateToken(token) {
  if (!token) return false;
  try {
    var payload = JSON.parse(Utilities.base64Decode(token));
    var now = new Date().getTime();
    var elapsed = now - payload.ts;
    var maxMs = SESSION_DURATION_HOURS * 60 * 60 * 1000;
    return elapsed < maxMs;
  } catch (e) {
    return false;
  }
}

/**
 * CheckService.gs — Perlu Cek Service
 * Validasi data ambigu, konversi ke KALDIK_NORMALIZED
 */

/**
 * Get Perlu Cek dengan filter
 */
function getPerluCek_(filters) {
  var allChecks = readSheet('PERLU_CEK');

  if (filters) {
    if (filters.tahunAjaran && filters.tahunAjaran !== 'all') {
      allChecks = allChecks.filter(function(c) { return c.TahunAjaran === filters.tahunAjaran; });
    }
    if (filters.bulan && filters.bulan !== 'all') {
      allChecks = allChecks.filter(function(c) { return c.Bulan == filters.bulan; });
    }
    if (filters.tahun && filters.tahun !== 'all') {
      allChecks = allChecks.filter(function(c) { return c.Tahun == filters.tahun; });
    }
    if (filters.unit && filters.unit !== 'all') {
      allChecks = allChecks.filter(function(c) { return c.Unit === filters.unit; });
    }
    if (filters.status && filters.status !== 'all') {
      allChecks = allChecks.filter(function(c) { return c.Status === filters.status; });
    }
  }

  return allChecks;
}

/**
 * Validasi Perlu Cek: konversi ke KALDIK_NORMALIZED
 * @param {string} id - CheckID
 * @param {object} fixedData - data yang sudah diperbaiki
 *   { TanggalMulai, TanggalSelesai, NamaKegiatan, Kategori, Unit, UnitScope,
 *     MasukPokokDoa, PrioritasDoa, CatatanDoa }
 */
function validatePerluCek_(id, fixedData) {
  if (!id) throw new Error('CheckID diperlukan');

  var checks = readSheet('PERLU_CEK');
  var checkItem = null;

  for (var i = 0; i < checks.length; i++) {
    if (checks[i].CheckID === id) {
      checkItem = checks[i];
      break;
    }
  }

  if (!checkItem) throw new Error('Item Perlu Cek tidak ditemukan: ' + id);

  // Build agenda data dari fix + original
  var now = new Date();
  var agendaData = {
    TahunAjaran: fixedData.TahunAjaran || checkItem.TahunAjaran || getSetting('TA_AKTIF') || '2026-2027',
    Bulan: fixedData.Bulan || checkItem.Bulan || (new Date().getMonth() + 1),
    Tahun: fixedData.Tahun || checkItem.Tahun || new Date().getFullYear(),
    Unit: fixedData.Unit || checkItem.Unit || 'U001',
    UnitScope: fixedData.UnitScope || 'UNIT',
    TanggalMulai: fixedData.TanggalMulai || null,
    TanggalSelesai: fixedData.TanggalSelesai || null,
    TanggalMentah: checkItem.TanggalMentah || null,
    NamaKegiatan: fixedData.NamaKegiatan || checkItem.NamaKegiatan || 'Tanpa Nama',
    Kategori: fixedData.Kategori || 'Umum',
    PrioritasDoa: fixedData.PrioritasDoa || 3,
    MasukPokokDoa: fixedData.MasukPokokDoa !== undefined ? fixedData.MasukPokokDoa : true,
    CatatanDoa: fixedData.CatatanDoa || null,
    Status: 'Valid',
    SumberData: 'Perlu Cek',
    CreatedAt: now,
    UpdatedAt: now
  };

  // Auto semester
  agendaData.Semester = agendaData.Bulan >= 7 ? 1 : 2;

  // Buat agenda di KALDIK_NORMALIZED
  agendaData.KaldikID = generateId('KAL');
  appendRow('KALDIK_NORMALIZED', agendaData);

  // Update status Perlu Cek ke Tervalidasi
  updateRow('PERLU_CEK', 'CheckID', id, {
    Status: 'Tervalidasi',
    Catatan: 'Telah divalidasi dan dipindahkan ke Kaldik. KaldikID: ' + agendaData.KaldikID,
    UpdatedAt: now
  });

  // Log
  writeChangeLog_('PERLU_CEK', id, 'VALIDATE', null, JSON.stringify({ KaldikID: agendaData.KaldikID }), 'Divalidasi ke KALDIK_NORMALIZED');

  return { CheckID: id, KaldikID: agendaData.KaldikID, message: 'Data tervalidasi dan dipindahkan ke Kaldik' };
}

/**
 * Abaikan item Perlu Cek
 */
function ignorePerluCek_(id) {
  if (!id) throw new Error('CheckID diperlukan');

  updateRow('PERLU_CEK', 'CheckID', id, {
    Status: 'Diabaikan',
    Catatan: 'Diabaikan oleh admin',
    UpdatedAt: new Date()
  });

  writeChangeLog_('PERLU_CEK', id, 'IGNORE', null, null, 'Diabaikan');

  return { CheckID: id, message: 'Item diabaikan' };
}

/**
 * Code.gs — Entry Point & Router
 * Aplikasi Kaldik & Pokok Doa Terpadu
 */

// Spreadsheet ID — disimpan di Script Properties
var SPREADSHEET_ID = PropertiesService.getScriptProperties().getProperty('SPREADSHEET_ID');

/**
 * doGet() — Menyajikan halaman web utama
 */
function doGet(e) {
  // Auto-init spreadsheet & sheets on first access
  // This must happen before any data operation
  ensureSheetsInitialized_();
  
  var page = e.parameter.page || 'index';
  var template;
  
  switch (page) {
    case 'index':
    default:
      template = HtmlService.createTemplateFromFile('Index');
      break;
  }
  
  return template
    .evaluate()
    .setTitle('Kaldik & Pokok Doa Terpadu')
    .setXFrameOptionsMode(HtmlService.XFrameOptionsMode.ALLOWALL)
    .addMetaTag('viewport', 'width=device-width, initial-scale=1.0')
    .setFaviconUrl('https://img.icons8.com/color/48/calendar.png');
}

/**
 * Ensure spreadsheet and sheets are initialized (idempotent)
 */
function ensureSheetsInitialized_() {
  try {
    var ss = getSpreadsheet();
    var settingSheet = ss.getSheetByName('SETTING');
    if (!settingSheet) {
      initSheets_();
      return;
    }
    
    // Check if data is corrupted (header row overwritten)
    var data = settingSheet.getDataRange().getValues();
    if (data.length >= 2 && data[0][0] !== 'Key') {
      // Header was overwritten — force re-init
      initSheets_();
    }
  } catch(e) {
    // Silent fail — will be handled by readSheet auto-init fallback
  }
}

/**
 * doPost() — API endpoint untuk semua aksi
 * Request body: { action: "namaAksi", data: { ... } }
 * 
 * DEPRECATED: Gunakan api_() via google.script.run untuk akses lebih reliable
 */
function doPost(e) {
  try {
    var postData;
    if (e.postData && e.postData.contents) {
      postData = JSON.parse(e.postData.contents);
    } else {
      throw new Error('No post data received');
    }
    
    var action = postData.action;
    var data = postData.data || {};
    
    var result = routeAction(action, data);
    return buildJsonResponse('success', result);
    
  } catch (error) {
    return buildJsonResponse('error', null, error.message || error.toString());
  }
}

/**
 * api() — Universal API handler untuk google.script.run
 * Client-side: google.script.run.api(action, data)
 * Return: { status, data, message } — kompatibel dengan format frontend
 */
function api(action, data) {
  try {
    var result = routeAction(action, data || {});
    var sanitized = sanitizeForClient_(result);
    return {
      status: 'success',
      data: sanitized,
      message: 'OK',
      timestamp: new Date().toISOString()
    };
  } catch (error) {
    return {
      status: 'error',
      data: null,
      message: error.message || error.toString(),
      timestamp: new Date().toISOString()
    };
  }
}

/**
 * Router — meneruskan action ke handler yang sesuai
 */
function routeAction(action, data) {
  switch (action) {
    // === AUTH ===
    case 'checkPin':
      return checkPin_(data.pin);
    case 'logout':
      return logout_();
    
    // === SETTING ===
    case 'getAppInfo':
      return getAppInfo_();
    case 'getSetting':
      return getSetting_(data.key);
    case 'updateSetting':
      return updateSetting_(data.key, data.value);
    
    // === INITIAL DATA (Optimasi Loading) ===
    case 'getInitialData':
      return getInitialData_();
    
    // === UNIT ===
    case 'getUnits':
      return getUnits_();
    
    // === DASHBOARD ===
    case 'getDashboard':
      return getDashboard_(data);
    
    // === KALDIK ===
    case 'getKaldik':
      return getKaldik_(data.filters || {});
    case 'getKaldikCalendarPayload':
      return getKaldikCalendarPayload_(data.filters || {});
    case 'addKaldik':
      return addKaldik_(data);
    case 'updateKaldik':
      return updateKaldik_(data.id, data);
    case 'duplicateKaldik':
      return duplicateKaldik_(data.id);
    case 'moveKaldikDate':
      return moveKaldikDate_(data.id, data.newStart, data.newEnd);
    case 'cancelKaldik':
      return cancelKaldik_(data.id);
    case 'bulkAddAgenda':
      return bulkAddAgenda_(data);
    case 'scanDuplicates':
      return scanDuplicates_();
    case 'archiveDuplicates':
      return archiveDuplicates_(data.ids);
    case 'fixDuplicateKaldikIds':
      return fixDuplicateKaldikIds_();
    
    // === KARYAWAN ===
    case 'getKaryawan':
      return getKaryawan_(data.filters || {});
    case 'addKaryawan':
      return addKaryawan_(data);
    case 'updateKaryawan':
      return updateKaryawan_(data);
    case 'deleteKaryawan':
      return deleteKaryawan_(data.id);
    case 'importKaryawanCsv':
      return importKaryawanCsvRoute_(data.csvText, data.options || {});
    case 'getBirthdayCalendar':
      return getBirthdayCalendar_(data.bulan, data.tahun);
    case 'getAllBirthdays':
      return getAllBirthdays_(data.filters || {});
    case 'getAllBirthdaysAcademicYear':
      return getAllBirthdaysAcademicYear_(data.filters || {});
    
    // === TEMA BULANAN ===
    case 'getTema':
      return getTema_(data.filters || {});
    case 'addTema':
      return addTema_(data);
    case 'updateTema':
      return updateTema_(data.id, data);
    case 'deleteTema':
      return deleteTema_(data.id);
    case 'bulkUpdateTemaBulanan':
      return bulkUpdateTemaBulanan_(data.rows);
    
    // === HARI KHUSUS ===
    case 'getHariKhusus':
      return getHariKhusus_(data.filters || {});
    
    // === PERLU CEK ===
    case 'getPerluCek':
      return getPerluCek_(data.filters || {});
    case 'validatePerluCek':
      return validatePerluCek_(data.id, data);
    case 'ignorePerluCek':
      return ignorePerluCek_(data.id);
    
    // === TANPA TANGGAL ===
    case 'getTanpaTanggal':
      return getTanpaTanggal_(data.filters || {});
    case 'convertNoteToAgenda':
      return convertNoteToAgenda_(data.id, data);
    case 'saveAsMonthlyNote':
      return saveAsMonthlyNote_(data.id, data.catatanAdmin);
    case 'ignoreNote':
      return ignoreNote_(data.id);
    
    // === POKOK DOA ===
    case 'getPokokDoa':
      return getPokokDoa_(data.filters || {});
    case 'generatePrayer':
      return generatePrayer_(data.month, data.year, data.unitMode, data.options || {});
    case 'regeneratePrayerDate':
      return regeneratePrayerDate_(data.date, data.unitMode, data.options || {});
    case 'updatePrayer':
      return updatePrayer_(data.id, data);
    case 'lockPrayer':
      return lockPrayer_(data.id);
    case 'unlockPrayer':
      return unlockPrayer_(data.id);
    case 'finalizePrayer':
      return finalizePrayer_(data.id);
    case 'finalizePrayerMonth':
      return finalizePrayerMonth_(data.month, data.year, data.unitMode);
    case 'initTemplates':
      return initTemplates_();
    
    // === EXPORT ===
    case 'exportPrayerHtml':
      return exportPrayerHtml_(data.month, data.year, data.unitMode);
    
    // === IMPORT ===
    case 'parseImportPreview':
      return parseImportPreview_(data.csvText);
    case 'executeImport':
      return executeImport_(data.csvText);
    
    // === SPREADSHEET ===
    case 'getSpreadsheetInfo':
      return getSpreadsheetInfo_();
    case 'reconnectSpreadsheet':
      return reconnectSpreadsheet_(data.spreadsheetId);
    
    // === INIT ===
    case 'initSheets':
      return initSheets_();
    case 'setupApp':
      return setupApp_();
    
    default:
      throw new Error('Action tidak dikenal: ' + action);
  }
}

/**
 * Include HTML helper — untuk menyertakan file HTML lain dalam template
 */
function include(filename) {
  return HtmlService.createHtmlOutputFromFile(filename).getContent();
}

/**
 * Get script property
 */
function getScriptProperty(key) {
  return PropertiesService.getScriptProperties().getProperty(key);
}

/**
 * Set script property
 */
function setScriptProperty(key, value) {
  PropertiesService.getScriptProperties().setProperty(key, value);
}

/**
 * Get Hari Khusus dengan filter opsional
 * @param {Object} filters - { month, year, jenis }
 * @return {Array} Filtered rows dari sheet HARI_KHUSUS
 */
function getHariKhusus_(filters) {
  var allHari = readSheet('HARI_KHUSUS');

  if (filters) {
    // Filter berdasarkan bulan + tahun
    if (filters.month && filters.year) {
      allHari = allHari.filter(function(h) {
        if (!h.Tanggal) return false;
        var tgl = new Date(h.Tanggal);
        return (tgl.getMonth() + 1) == filters.month && tgl.getFullYear() == filters.year;
      });
    } else if (filters.month) {
      allHari = allHari.filter(function(h) {
        if (!h.Tanggal) return false;
        var tgl = new Date(h.Tanggal);
        return (tgl.getMonth() + 1) == filters.month;
      });
    } else if (filters.year) {
      allHari = allHari.filter(function(h) {
        if (!h.Tanggal) return false;
        var tgl = new Date(h.Tanggal);
        return tgl.getFullYear() == filters.year;
      });
    }

    // Filter berdasarkan jenis
    if (filters.jenis && filters.jenis !== 'all') {
      allHari = allHari.filter(function(h) {
        return h.Jenis === filters.jenis;
      });
    }
  }

  return allHari;
}

/**
 * ExportService.gs — Export Pokok Doa
 * HTML printable, format kalender bulanan (Senin-Minggu)
 */

/**
 * Generate HTML kalender Pokok Doa siap print
 * @param {number} month - 1-12
 * @param {number} year - tahun masehi
 * @param {string} unitMode - Gabungan Semua Unit / Universal / TK / SD / SMP
 * @return {object} { html: string }
 */
function exportPrayerHtml_(month, year, unitMode) {
  if (!month || !year || !unitMode) {
    throw new Error('Bulan, tahun, dan unitMode wajib diisi');
  }

  var prayers = readSheet('POKOK_DOA').filter(function(p) {
    return p.Bulan == month && p.Tahun == year && p.UnitMode === unitMode;
  });

  // Index by day
  var prayerMap = {};
  prayers.forEach(function(p) {
    var d = p.Tanggal ? new Date(p.Tanggal).getDate() : null;
    if (d) prayerMap[d] = p;
  });

  var bulanNames = ['', 'Januari', 'Februari', 'Maret', 'April', 'Mei', 'Juni',
                    'Juli', 'Agustus', 'September', 'Oktober', 'November', 'Desember'];
  var dayNames = ['Minggu', 'Senin', 'Selasa', 'Rabu', 'Kamis', 'Jumat', 'Sabtu'];
  var shortDayNames = ['Min', 'Sen', 'Sel', 'Rab', 'Kam', 'Jum', 'Sab'];

  var firstDay = new Date(year, month - 1, 1).getDay(); // 0 = Minggu
  var totalDays = new Date(year, month, 0).getDate();

  // Build HTML
  var html = buildExportHtml(month, year, unitMode, bulanNames, shortDayNames, dayNames, firstDay, totalDays, prayerMap);

  return { html: html };
}

function buildExportHtml(month, year, unitMode, bulanNames, shortDayNames, dayNames, firstDay, totalDays, prayerMap) {
  var h = '';

  h += '<!DOCTYPE html>\n';
  h += '<html lang="id">\n<head>\n';
  h += '<meta charset="UTF-8">\n';
  h += '<meta name="viewport" content="width=device-width, initial-scale=1.0">\n';
  h += '<title>Pokok Doa - ' + bulanNames[month] + ' ' + year + '</title>\n';
  h += '<style>\n';
  h += getExportCss();
  h += '</style>\n';
  h += '</head>\n<body>\n';

  // Header
  h += '<div class="print-header">\n';
  h += '<h1>Pokok Doa</h1>\n';
  h += '<h2>' + bulanNames[month] + ' ' + year + '</h2>\n';
  h += '<p class="subtitle">' + unitMode + ' &mdash; Kaldik &amp; Pokok Doa Terpadu TK-SD-SMP</p>\n';
  h += '</div>\n';

  // Calendar Table
  h += '<table class="calendar-table">\n';

  // Day headers
  h += '<thead><tr>\n';
  for (var d = 0; d < 7; d++) {
    var cls = (d === 0 || d === 6) ? ' class="weekend"' : '';
    h += '<th' + cls + '>' + shortDayNames[d] + '</th>\n';
  }
  h += '</tr></thead>\n';

  h += '<tbody>\n';

  var day = 1;
  var rowCount = Math.ceil((firstDay + totalDays) / 7);

  for (var r = 0; r < rowCount; r++) {
    h += '<tr>\n';
    for (var c = 0; c < 7; c++) {
      var cellIndex = r * 7 + c;

      if (cellIndex < firstDay || day > totalDays) {
        h += '<td class="empty-cell"></td>\n';
      } else {
        var dateObj = new Date(year, month - 1, day);
        var dayName = dayNames[dateObj.getDay()];
        var isWeekend = dateObj.getDay() === 0 || dateObj.getDay() === 6;
        var p = prayerMap[day];

        h += '<td class="day-cell' + (isWeekend ? ' weekend' : '') + '">\n';
        h += '<div class="day-number">' + day + '</div>\n';
        h += '<div class="day-name">' + dayName + '</div>\n';

        if (p) {
          var judul = p.Judul || '';
          var isiDoa = p.IsiDoa || '';
          var sumber = p.SumberData || '';
          var status = p.StatusDoa || '';

          h += '<div class="prayer-content">\n';
          if (judul) {
            h += '<div class="prayer-title">' + escapeHtmlExport(judul) + '</div>\n';
          }
          h += '<div class="prayer-text">' + escapeHtmlExport(isiDoa) + '</div>\n';
          h += '</div>\n';

          // Label kecil
          var sumberLabel = sumber.replace('Template ', '');
          var labelClass = '';
          if (status === 'Final') labelClass = ' label-final';
          else if (status === 'Edited Manual') labelClass = ' label-edited';

          h += '<div class="day-labels">\n';
          h += '<span class="label' + labelClass + '">' + escapeHtmlExport(sumberLabel) + '</span>\n';
          if (status === 'Final') {
            h += '<span class="label label-final">Final</span>\n';
          }
          h += '</div>\n';
        } else {
          h += '<div class="prayer-empty">—</div>\n';
        }

        h += '</td>\n';
        day++;
      }
    }
    h += '</tr>\n';
  }

  h += '</tbody>\n';
  h += '</table>\n';

  // Footer
  h += '<div class="print-footer">\n';
  h += '<p>Dicetak pada: ' + formatDateReadableExport(new Date()) + '</p>\n';
  h += '</div>\n';

  h += '</body>\n</html>';

  return h;
}

function getExportCss() {
  return ''
    + '* { box-sizing: border-box; margin: 0; padding: 0; }\n'
    + 'body { font-family: "Segoe UI", Roboto, Arial, sans-serif; font-size: 10pt; color: #1E293B; padding: 15px; max-width: 210mm; margin: 0 auto; }\n'
    + '.print-header { text-align: center; margin-bottom: 16px; padding-bottom: 12px; border-bottom: 2px solid #4F46E5; }\n'
    + '.print-header h1 { font-size: 18pt; color: #4F46E5; margin-bottom: 2px; }\n'
    + '.print-header h2 { font-size: 14pt; color: #1E293B; margin-bottom: 2px; }\n'
    + '.print-header .subtitle { font-size: 8pt; color: #64748B; }\n'
    + '.calendar-table { width: 100%; border-collapse: collapse; table-layout: fixed; }\n'
    + '.calendar-table th { font-size: 7pt; font-weight: 600; color: #64748B; text-align: center; padding: 6px 2px; border: 1px solid #CBD5E1; background: #F1F5F9; }\n'
    + '.calendar-table th.weekend { color: #EF4444; }\n'
    + '.day-cell { vertical-align: top; padding: 6px 4px; border: 1px solid #CBD5E1; height: 110px; width: 14.28%; }\n'
    + '.day-cell.weekend { background: #FEF2F2; }\n'
    + '.empty-cell { border: 1px solid #CBD5E1; background: #F8FAFC; }\n'
    + '.day-number { font-size: 10pt; font-weight: 700; color: #1E293B; margin-bottom: 1px; }\n'
    + '.day-name { font-size: 6pt; color: #94A3B8; margin-bottom: 4px; }\n'
    + '.prayer-content { margin-bottom: 4px; }\n'
    + '.prayer-title { font-size: 7pt; font-weight: 600; color: #4F46E5; margin-bottom: 1px; }\n'
    + '.prayer-text { font-size: 7pt; line-height: 1.35; color: #334155; }\n'
    + '.prayer-empty { font-size: 7pt; color: #CBD5E1; text-align: center; padding-top: 10px; }\n'
    + '.day-labels { display: flex; gap: 2px; flex-wrap: wrap; margin-top: 4px; }\n'
    + '.label { font-size: 5.5pt; padding: 0px 4px; border-radius: 2px; background: #E2E8F0; color: #475569; display: inline-block; }\n'
    + '.label-final { background: #D1FAE5; color: #065F46; }\n'
    + '.label-edited { background: #FEF3C7; color: #92400E; }\n'
    + '.print-footer { margin-top: 12px; padding-top: 8px; border-top: 1px solid #E2E8F0; text-align: center; font-size: 7pt; color: #94A3B8; }\n'
    + '@media print {\n'
    + '  body { padding: 0; }\n'
    + '  @page { size: A4 landscape; margin: 8mm; }\n'
    + '  .calendar-table { page-break-inside: avoid; }\n'
    + '  .day-cell { height: 100px; }\n'
    + '}\n';
}

function escapeHtmlExport(str) {
  if (!str) return '';
  return String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/\n/g, '<br>');
}

function formatDateReadableExport(date) {
  var d = new Date(date);
  var bulan = ['Januari','Februari','Maret','April','Mei','Juni','Juli','Agustus','September','Oktober','November','Desember'];
  return d.getDate() + ' ' + bulan[d.getMonth()] + ' ' + d.getFullYear() + ' ' +
         ('0' + d.getHours()).slice(-2) + ':' + ('0' + d.getMinutes()).slice(-2);
}

