/**
 * Auto-detect delimiter: comma (,) atau semicolon (;)
 */
function detectDelimiter_(csvText) {
  var firstLine = csvText.split('\n')[0] || '';
  var commas = (firstLine.match(/,/g) || []).length;
  var semicolons = (firstLine.match(/;/g) || []).length;
  return semicolons > commas ? ';' : ',';
}

/**
 * Parse CSV text dan return preview + summary
 * @param {string} csvText - Raw CSV text
 * @return {object} { headers, totalRows, validRows, errors[], preview[] }
 */
function parseImportPreview_(csvText) {
  if (!csvText || csvText.trim() === '') {
    throw new Error('Data kosong. Paste CSV atau upload file terlebih dahulu.');
  }

  // Parse CSV (auto-detect delimiter, bersihkan \r Windows)
  var raw;
  try {
    var cleanText = csvText.replace(/\r/g, '');
    var delimiter = detectDelimiter_(cleanText);
    raw = Utilities.parseCsv(cleanText, delimiter);
  } catch (e) {
    throw new Error('Gagal parse CSV: ' + e.message);
  }

  if (raw.length < 2) {
    throw new Error('CSV minimal harus punya header + 1 baris data.');
  }

  // Extract headers
  var srcHeaders = raw[0].map(function(h) { return String(h).trim(); });

  // Validate required headers
  var requiredHeaders = ['NamaKegiatan', 'TanggalMulai', 'BulanAngka'];
  var missingHeaders = [];
  requiredHeaders.forEach(function(req) {
    if (srcHeaders.indexOf(req) === -1) missingHeaders.push(req);
  });

  if (missingHeaders.length > 0) {
    throw new Error('Header wajib tidak ditemukan: ' + missingHeaders.join(', ') +
      '\n\nHeader Anda:\n' + srcHeaders.join(', '));
  }

  // Validate header mapping
  var unrecognized = [];
  srcHeaders.forEach(function(h) {
    if (!HEADER_MAPPING[h]) unrecognized.push(h);
  });

  // Capture debug: raw row pertama + headers
  var debugHeaders = raw[0].map(function(h) { return String(h).trim(); });
  var debugFirstRow = raw.length > 1 ? raw[1].map(function(v) { return v != null ? String(v).substring(0, 80) : '(empty)'; }) : [];
  var debugMapped = {};
  if (raw.length > 1) {
    debugHeaders.forEach(function(h, i) {
      var m = HEADER_MAPPING[h];
      var rawVal = raw[1][i] !== undefined && raw[1][i] !== null ? String(raw[1][i]).trim() : '';
      if (m && m.transform !== 'skip' && m.transform !== 'ignore') {
        var t = applyTransform(m.transform, rawVal, h);
        if (t) {
          debugMapped[h] = t.error || (t.value != null ? String(t.value).substring(0, 60) : '(null)');
        } else {
          debugMapped[h] = 'null';
        }
      }
    });
  }

  // Process rows
  var dataRows = raw.slice(1);
  var errors = [];
  var validRows = [];
  var skippedNoNama = 0;
  var skippedNoTanggal = 0;
  var skippedBadUnit = 0;
  var skippedBadDate = 0;

  dataRows.forEach(function(row, idx) {
    var lineNum = idx + 2; // CSV line number (1-based, header is line 1)
    var mapped = {};
    var rowErrors = [];

    // Build mapped object
    srcHeaders.forEach(function(header, colIdx) {
      var mapping = HEADER_MAPPING[header];
      if (!mapping || mapping.transform === 'skip' || mapping.transform === 'ignore') return;

      var rawVal = row[colIdx] !== undefined ? String(row[colIdx]).trim() : '';
      var transformed = applyTransform(mapping.transform, rawVal, header);

      if (!transformed) {
        rowErrors.push(header + ': internal error');
        return;
      }
      if (transformed.error) {
        rowErrors.push(header + ': ' + transformed.error);
        return;
      }

      mapped[header] = transformed.value;
      // PATCH 6: Simpan display name untuk Unit
      if (header === 'Unit' && transformed.display) {
        mapped['UnitDisplay'] = transformed.display;
      }
    });

    // Check required fields
    var namaKegiatan = (mapped['NamaKegiatan'] || '').trim();
    var tanggalMulai = toDate(mapped['TanggalMulai']);

    if (!namaKegiatan) {
      skippedNoNama++;
      return;
    }

    if (!tanggalMulai) {
      skippedNoTanggal++;
      return;
    }

    // Check unit valid
    var unitVal = mapped['Unit'];
    if (unitVal === undefined || unitVal === null) {
      skippedBadUnit++;
      return;
    }

    if (rowErrors.length > 0) {
      errors.push({ line: lineNum, errors: rowErrors, data: namaKegiatan });
      return;
    }

    // Build target Kaldik row
    var kaldikRow = buildKaldikRow(mapped, srcHeaders, row);
    validRows.push(kaldikRow);
  });

  // Build preview (max 5 rows) — PATCH 6: tampilkan UnitDisplay, bukan UnitRaw
  var preview = validRows.slice(0, 5).map(function(r) {
    return {
      NamaKegiatan: r.NamaKegiatan || '',
      Unit: r.UnitDisplay || r.Unit || '',
      TanggalMulai: r.TanggalMulai ? fmtDate(r.TanggalMulai) : '',
      Kategori: r.Kategori || '',
      Status: r.Status || '',
      MasukDoa: r.MasukPokokDoa ? 'Ya' : 'Tidak'
    };
  });

  var hasTema = validRows.some(function(r) {
    var temaFields = r._tema || {};
    return temaFields.Tema || temaFields.Profil || temaFields.Karakter ||
           temaFields.BESTRA || temaFields.HBE || temaFields.HM;
  });

  return {
    srcHeaders: srcHeaders,
    recognizedHeaders: srcHeaders.filter(function(h) { return HEADER_MAPPING[h] && HEADER_MAPPING[h].transform !== 'ignore'; }),
    unrecognizedHeaders: unrecognized,
    totalRows: dataRows.length,
    validCount: validRows.length,
    skippedNoNama: skippedNoNama,
    skippedNoTanggal: skippedNoTanggal,
    skippedBadUnit: skippedBadUnit,
    hasTemaData: hasTema,
    parseErrors: errors,
    preview: preview,
    _debug: {
      version: '0.9.8',
      headerCount: debugHeaders.length,
      headers: debugHeaders,
      firstRow: debugFirstRow,
      mapped: debugMapped,
      dateTest: (function() {
        var input = '2026-06-29';
        var parsed = parseImportDate_(input);
        var dt = toDate(parsed ? parsed.value : null);
        return JSON.stringify({
          input: input,
          parsed: parsed,
          parsedValue: parsed ? parsed.value : null,
          parsedError: parsed ? parsed.error : null,
          toDateResult: dt ? fmtDate(dt) : null,
          toDateValid: dt instanceof Date && !isNaN(dt.getTime())
        });
      })()
    }
  };
}

// ============================================================
// EXECUTE IMPORT
