/**
 * Execute import — write data ke sheet
 * @param {string} csvText - Raw CSV text
 * @return {object} { total, success, kaldikCount, temaCount, skipped, errors[] }
 */
function executeImport_(csvText) {
  // Re-parse (auto-detect delimiter, bersihkan \r)
  var cleanText = csvText.replace(/\r/g, '');
  var delimiter = detectDelimiter_(cleanText);
  var raw = Utilities.parseCsv(cleanText, delimiter);
  var srcHeaders = raw[0].map(function(h) { return String(h).trim(); });
  var dataRows = raw.slice(1);

  var ss = getSpreadsheet();
  var kaldikSheet = ss.getSheetByName('KALDIK_NORMALIZED');
  var temaSheet = ss.getSheetByName('TEMA_BULANAN');

  if (!kaldikSheet) throw new Error('Sheet KALDIK_NORMALIZED tidak ditemukan. Jalankan Inisialisasi Sheet dulu.');

  // Get existing KaldikIDs (untuk cek duplikat — meskipun kita generate baru, 
  // tapi kita cek NamaKegiatan+TanggalMulai+Unit untuk hindari duplikat konten)
  var existingData = kaldikSheet.getDataRange().getValues();
  var existingKeys = {};
  if (existingData.length > 1) {
    var headers = existingData[0];
    var namaIdx = headers.indexOf('NamaKegiatan');
    var tglIdx = headers.indexOf('TanggalMulai');
    var unitIdx = headers.indexOf('Unit');
    for (var i = 1; i < existingData.length; i++) {
      var key = String(existingData[i][namaIdx] || '').trim().toLowerCase() + '|' +
                String(existingData[i][tglIdx] || '') + '|' +
                String(existingData[i][unitIdx] || '').trim().toLowerCase();
      existingKeys[key] = true;
    }
  }

  var kaldikRows = [];
  var temaRows = [];
  var skipped = { noNama: 0, noTanggal: 0, badUnit: 0, duplicate: 0 };
  var errors = [];
  var now = new Date();

  dataRows.forEach(function(row, idx) {
    var lineNum = idx + 2;
    var mapped = {};
    var rowErrors = [];

    srcHeaders.forEach(function(header, colIdx) {
      var mapping = HEADER_MAPPING[header];
      if (!mapping || mapping.transform === 'skip' || mapping.transform === 'ignore') return;

      var rawVal = row[colIdx] !== undefined ? String(row[colIdx]).trim() : '';
      var transformed = applyTransform(mapping.transform, rawVal, header);

      if (!transformed) {
        rowErrors.push(header + ': internal error');
        return;
      }
      if (transformed.error) {
        rowErrors.push(header + ': ' + transformed.error);
        return;
      }

      mapped[header] = transformed.value;
      // PATCH 6: Simpan display name untuk Unit
      if (header === 'Unit' && transformed.display) {
        mapped['UnitDisplay'] = transformed.display;
      }
    });

    var namaKegiatan = (mapped['NamaKegiatan'] || '').trim();
    var tanggalMulai = toDate(mapped['TanggalMulai']);
    var tanggalSelesai = toDate(mapped['TanggalSelesai']);
    var unitVal = mapped['Unit'];
    var unitDisplay = mapped['UnitDisplay'] || normalizeUnit(unitVal) || '';

    if (!namaKegiatan) { skipped.noNama++; return; }
    if (!tanggalMulai) { skipped.noTanggal++; return; }
    if (unitVal === undefined || unitVal === null) { skipped.badUnit++; return; }
    if (rowErrors.length > 0) { errors.push({ line: lineNum, errors: rowErrors, data: namaKegiatan }); return; }

    // Cek duplikat
    var dupKey = namaKegiatan.toLowerCase() + '|' + String(tanggalMulai) + '|' + unitVal.toLowerCase();
    if (existingKeys[dupKey]) {
      skipped.duplicate++;
      return;
    }
    existingKeys[dupKey] = true;

    // Build Kaldik row
    var semester = mapped['Semester'] || (mapped['BulanAngka'] >= 7 ? 1 : 2);
    var bulan = mapped['BulanAngka'] || (tanggalMulai ? tanggalMulai.getMonth() + 1 : 1);
    var tahun = mapped['Tahun'] || (tanggalMulai ? tanggalMulai.getFullYear() : new Date().getFullYear());
    var tahunAjaran = mapped['TahunAjaran'] || buildTahunAjaran(bulan, tahun);

    var kaldikRow = [
      generateId('KAL-'),                          // KaldikID (baru)
      tahunAjaran,                                  // TahunAjaran
      semester,                                     // Semester
      bulan,                                        // Bulan
      tahun,                                        // Tahun
      unitVal,                                      // Unit
      'UNIT',                                       // UnitScope (default)
      tanggalMulai,                                 // TanggalMulai
      tanggalSelesai || null,                       // TanggalSelesai
      mapped['TanggalAsli'] || null,                // TanggalMentah
      namaKegiatan,                                 // NamaKegiatan
      mapped['Kategori'] || 'Umum',                 // Kategori
      mapped['PrioritasDoa'] || 3,                  // PrioritasDoa
      mapped['MasukPokokDoa'] !== undefined ? mapped['MasukPokokDoa'] : true, // MasukPokokDoa
      mapped['CatatanNormalisasi'] || null,         // CatatanDoa
      mapped['StatusValidasi'] || 'Draft',          // Status
      mapped['SumberCell'] || 'Import',             // SumberData
      now,                                          // CreatedAt
      now                                           // UpdatedAt
    ];

    kaldikRows.push(kaldikRow);

    // Build Tema row (jika ada data tema)
    var temaFields = {
      Tema: mapped['TemaBulan'] || '',
      Profil: mapped['Profil'] || '',
      Karakter: mapped['Karakter'] || '',
      BESTRA: mapped['BESTRA'] || '',
      HBE: mapped['HBE'] || '',
      HM: mapped['HM'] || ''
    };

    var hasTema = temaFields.Tema || temaFields.Profil || temaFields.Karakter ||
                  temaFields.BESTRA || temaFields.HBE || temaFields.HM;

    if (hasTema) {
      var temaRow = [
        generateId('TMA-'),          // TemaID
        tahunAjaran,                  // TahunAjaran
        semester,                     // Semester
        bulan,                        // Bulan
        tahun,                        // Tahun
        unitVal,                      // Unit
        temaFields.Tema || null,      // Tema
        null,                         // Ayat (kosong)
        temaFields.Profil || null,    // Profil
        temaFields.Karakter || null,  // Karakter
        temaFields.BESTRA || null,    // BESTRA
        temaFields.HBE || null,       // HBE
        temaFields.HM || null,        // HM
        null,                         // CatatanTema (kosong)
        'Draft',                      // Status
        now                           // UpdatedAt
      ];
      temaRows.push(temaRow);
    }
  });

  // Write to sheets
  if (kaldikRows.length > 0) {
    var lastRow = kaldikSheet.getLastRow();
    kaldikSheet.getRange(lastRow + 1, 1, kaldikRows.length, kaldikRows[0].length).setValues(kaldikRows);
  }

  if (temaRows.length > 0 && temaSheet) {
    var lastTemaRow = temaSheet.getLastRow();
    temaSheet.getRange(lastTemaRow + 1, 1, temaRows.length, temaRows[0].length).setValues(temaRows);
  }

  return {
    total: dataRows.length,
    success: kaldikRows.length,
    kaldikCount: kaldikRows.length,
    temaCount: temaRows.length,
    skipped: skipped,
    errors: errors
  };
}

// ============================================================
// TRANSFORMS
// ============================================================

function applyTransform(transform, value, header) {
  if (value === '' || value === undefined || value === null) {
    // Allow empty for optional fields
    if (transform === 'dateOrNull' || transform === 'directOrNull' || transform === 'prioritas') {
      return { value: null };
    }
    // Required fields return empty (validated later)
    if (transform === 'direct' && header === 'TemaBulan') return { value: null };
    if (transform === 'direct' && header === 'Profil') return { value: null };
    if (transform === 'direct' && header === 'Karakter') return { value: null };
    if (transform === 'direct' && header === 'BESTRA') return { value: null };
    if (transform === 'direct' && header === 'HBE') return { value: null };
    if (transform === 'direct' && header === 'HM') return { value: null };
  }

  switch (transform) {
    case 'direct':
      return { value: value };
    case 'directOrNull':
      return { value: value || null };
    case 'number':
      var num = Number(value);
      return isNaN(num) ? { error: 'Bukan angka: ' + value } : { value: num };
    case 'semester':
      return mapSemester(value);
    case 'date':
      return parseImportDate_(value);
    case 'dateOrNull':
      if (!value || value === '-' || value === '') return { value: null };
      return parseImportDate_(value);
    case 'boolean':
      var v = String(value).toLowerCase().trim();
      return { value: v === 'true' || v === '1' || v === 'ya' || v === 'yes' || v === 'y' };
    case 'mapUnit':
      return mapUnit(value);
    case 'mapStatus':
      return mapStatus(value);
    case 'prioritas':
      if (!value || value === '') return { value: 3 };
      var p = Number(value);
      if (isNaN(p) || p < 1 || p > 5) return { value: 3 }; // default
      return { value: p };
    case 'sumberData':
      return { value: value ? 'Import: ' + value : 'Import' };
    default:
      return { value: value };
  }
}

function parseImportDate_(value) {
  if (!value || value === '') return { error: 'Tanggal kosong' };
  var str = String(value).trim();

  // Split pakai indexOf (hindari masalah regex/split di GAS V8)
  var sep = str.indexOf('-');
  if (sep === -1) sep = str.indexOf('/');
  if (sep === -1) sep = str.indexOf('.');

  if (sep > 0) {
    var sep2 = str.indexOf('-', sep + 1);
    if (sep2 === -1) sep2 = str.indexOf('/', sep + 1);
    if (sep2 === -1) sep2 = str.indexOf('.', sep + 1);

    if (sep2 > sep) {
      var p0 = Number(str.substring(0, sep));
      var p1 = Number(str.substring(sep + 1, sep2));
      var p2 = Number(str.substring(sep2 + 1));

      if (!isNaN(p0) && !isNaN(p1) && !isNaN(p2)) {
        var dt = null;
        if (p0 > 1000 && p0 < 9999 && p1 >= 1 && p1 <= 12 && p2 >= 1 && p2 <= 31) {
          dt = new Date(p0, p1 - 1, p2);        // YYYY-MM-DD
        } else if (p2 > 1000 && p2 < 9999 && p1 >= 1 && p1 <= 12 && p0 >= 1 && p0 <= 31) {
          dt = new Date(p2, p1 - 1, p0);        // DD/MM/YYYY
        } else if (p2 >= 0 && p2 <= 99 && p1 >= 1 && p1 <= 12 && p0 >= 1 && p0 <= 31) {
          dt = new Date(2000 + p2, p1 - 1, p0);  // DD/MM/YY
        }
        if (dt && !isNaN(dt.getTime())) {
          // Kembalikan timestamp angka, bukan Date object
          // (GAS V8 serialization bisa corrupt {value: Date})
          return { value: dt.getTime() };
        }
      }
    }
  }

  // Fallback native
  var d = new Date(str);
  if (!isNaN(d.getTime())) {
    return { value: d.getTime() };
  }

  return { error: 'Format tanggal tidak dikenal: ' + str };
}

/**
 * Konversi timestamp number (dari parseDate) ke Date object.
 * Aman untuk null/undefined/Date yang sudah jadi.
 */
function toDate(val) {
  if (val === null || val === undefined) return null;
  if (val instanceof Date) return val;
  if (typeof val === 'number') return new Date(val);
  if (typeof val === 'string') {
    var n = Number(val);
    if (!isNaN(n)) return new Date(n);
  }
  return null;
}

/**
 * Format Date ke string DD/MM/YYYY (untuk preview).
 */
function fmtDate(val) {
  var d = toDate(val);
  if (!d) return '';
  var dd = String(d.getDate()).padStart(2, '0');
  var mm = String(d.getMonth() + 1).padStart(2, '0');
  var yyyy = d.getFullYear();
  return dd + '/' + mm + '/' + yyyy;
}

function mapUnit(value) {
  var str = String(value).trim();
  var lower = str.toLowerCase();

  var rawUnit = null;

  // Check exact match first
  if (UNIT_MAP[lower]) {
    rawUnit = UNIT_MAP[lower];
  }

  // Try partial match
  if (!rawUnit) {
    if (lower.indexOf('tk') !== -1 || lower.indexOf('toddler') !== -1 || lower.indexOf('kb') !== -1) {
      rawUnit = 'U002';
    } else if (lower.indexOf('sd') !== -1) {
      rawUnit = 'U003';
    } else if (lower.indexOf('smp') !== -1) {
      rawUnit = 'U004';
    } else if (lower.indexOf('manajemen') !== -1 || lower.indexOf('mng') !== -1 || lower.indexOf('management') !== -1) {
      rawUnit = 'U005';
    } else if (lower.indexOf('universal') !== -1 || lower.indexOf('uni') !== -1) {
      rawUnit = 'U001';
    } else if (lower.indexOf('tbi') !== -1) {
      rawUnit = 'U006';
    } else if (lower.indexOf('rts') !== -1) {
      rawUnit = 'U007';
    }
  }

  if (!rawUnit) {
    return { error: 'Unit tidak dikenal: "' + str + '". Dikenali: TK, SD, SMP, TBI, RTS, Manajemen, Universal' };
  }

  // Normalize to display name via global normalizeUnit()
  var display = normalizeUnit(rawUnit);

  // Validate display name
  if (VALID_UNITS.indexOf(display) === -1) {
    return { error: 'Unit "' + display + '" bukan unit valid. Dikenali: ' + VALID_UNITS.join(', ') };
  }

  return {
    value: rawUnit,
    display: display
  };
}

function mapStatus(value) {
  var str = String(value).trim();
  var lower = str.toLowerCase();
  if (STATUS_MAP[lower]) return { value: STATUS_MAP[lower] };

  // Default to Draft if unrecognized
  return { value: 'Draft' };
}

function mapSemester(value) {
  var num = Number(value);
  if (!isNaN(num) && (num === 1 || num === 2)) return { value: num };
  var str = String(value).trim().toLowerCase();
  var semMap = {
    'ganjil': 1, 'gasal': 1, '1': 1, 'satu': 1,
    'genap': 2, '2': 2, 'dua': 2
  };
  if (semMap[str] !== undefined) return { value: semMap[str] };
  return { error: 'Semester tidak dikenal: "' + value + '". Gunakan: Ganjil, Genap, 1, atau 2' };
}

