/**
 * Get all employees with optional filters
 */
function getKaryawan_(filters) {
  var rows = readSheet('KARYAWAN');
  filters = filters || {};

  var bulan = filters.bulan || 'Semua Bulan';
  var search = (filters.search || '').trim().toLowerCase();
  var activeYear = filters.tahun || new Date().getFullYear();

  // Filter bulan
  if (bulan && bulan !== 'Semua Bulan' && bulan !== 'all') {
    var monthNum = normalizeMonth_(bulan);
    if (monthNum) {
      rows = rows.filter(function(r) {
        if (!r.TanggalLahir) return false;
        var d = new Date(r.TanggalLahir);
        return (d.getMonth() + 1) === monthNum;
      });
    }
  }

  // Search by name
  if (search) {
    rows = rows.filter(function(r) {
      var full = String(r.NamaLengkap || '').toLowerCase();
      var nick = String(r.NamaPanggilan || '').toLowerCase();
      return full.indexOf(search) >= 0 || nick.indexOf(search) >= 0;
    });
  }

  // Add display fields
  rows.forEach(function(r) {
    r.TanggalLahirIso = normalizeTanggalIso_(r.TanggalLahir);
    r.TanggalLahirIndo = formatTanggalIndonesia_(r.TanggalLahirIso);
    r.NamaTampil = String(r.NamaPanggilan || r.NamaLengkap || '').trim();
    r.BulanLahir = r.TanggalLahirIso ? parseInt(r.TanggalLahirIso.substring(5, 7)) : null;
    r.HariLahir = r.TanggalLahirIso ? parseInt(r.TanggalLahirIso.substring(8, 10)) : null;
  });

  return rows;
}

/**
 * Add a new employee
 */
function addKaryawan_(data) {
  if (!data.namaLengkap || !String(data.namaLengkap).trim()) {
    return { success: false, message: 'Nama lengkap wajib diisi' };
  }
  if (!data.tanggalLahir) {
    return { success: false, message: 'Tanggal lahir wajib diisi' };
  }

  var isoDate = normalizeTanggalIso_(data.tanggalLahir);
  if (!isoDate) {
    return { success: false, message: 'Format tanggal lahir tidak valid. Gunakan yyyy-mm-dd.' };
  }

  var now = new Date();
  var id = generateId('KAR');
  var record = {
    KaryawanID: id,
    NamaLengkap: String(data.namaLengkap).trim(),
    NamaPanggilan: String(data.namaPanggilan || '').trim() || String(data.namaLengkap).trim(),
    TanggalLahir: isoDate,
    CreatedAt: now,
    UpdatedAt: now
  };

  appendRow('KARYAWAN', record);
  clearRelatedCaches_('KARYAWAN');
