/**
 * Update employee
 */
function updateKaryawan_(data) {
  if (!data.id) {
    return { success: false, message: 'ID karyawan diperlukan' };
  }
  if (!data.namaLengkap || !String(data.namaLengkap).trim()) {
    return { success: false, message: 'Nama lengkap wajib diisi' };
  }
  if (!data.tanggalLahir) {
    return { success: false, message: 'Tanggal lahir wajib diisi' };
  }

  var isoDate = normalizeTanggalIso_(data.tanggalLahir);
  if (!isoDate) {
    return { success: false, message: 'Format tanggal lahir tidak valid.' };
  }

  var allRows = readSheet('KARYAWAN');
  var found = false;
  allRows.forEach(function(r) {
    if (r.KaryawanID === data.id) {
      r.NamaLengkap = String(data.namaLengkap).trim();
      r.NamaPanggilan = String(data.namaPanggilan || '').trim() || String(data.namaLengkap).trim();
      r.TanggalLahir = isoDate;
      r.UpdatedAt = new Date();
      found = true;
    }
  });

  if (!found) {
    return { success: false, message: 'Karyawan tidak ditemukan' };
  }

  // Write back
  writeSheetData_('KARYAWAN', allRows);
  clearRelatedCaches_('KARYAWAN');
