// ============================================================
// GENERATE ENGINE
// ============================================================

/**
 * Generate Pokok Doa untuk satu bulan
 * @param {number} month - 1-12
 * @param {number} year - tahun masehi
 * @param {string} unitMode - 'Gabungan Semua Unit' | 'Universal' | 'TK' | 'SD' | 'SMP'
 * @param {object} options - { overwriteAutoDraft: bool, skipEdited: bool, skipFinal: bool }
 */
function generatePrayer_(month, year, unitMode, options) {
  if (!month || !year || !unitMode) {
    throw new Error('Bulan, tahun, dan unitMode wajib diisi');
  }

  options = options || {};
  var overwriteAutoDraft = options.overwriteAutoDraft !== false; // default true
  var skipEdited = options.skipEdited !== false; // default true (skip edited)
  var skipFinal = options.skipFinal !== false; // default true (skip final)

  var unitMap = { 'Universal': 'U001', 'TK': 'U002', 'SD': 'U003', 'SMP': 'U004' };
  var targetUnit = unitMap[unitMode] || 'U001';

  // Load semua sumber data
  var allKaldik = readSheet('KALDIK_NORMALIZED');
  var allHariKhusus = readSheet('HARI_KHUSUS');
  var allKaryawan = readSheet('KARYAWAN');
  var allTemplates = readSheet('TEMPLATE_DOA');
  var existingPrayers = readSheet('POKOK_DOA').filter(function(p) {
    return p.Bulan == month && p.Tahun == year && p.UnitMode === unitMode;
  });
  var allTema = readSheet('TEMA_BULANAN');

  // Filter tema untuk bulan ini
  var temaBulanIni = allTema.filter(function(t) { return t.Bulan == month && t.Tahun == year; });

  var totalDays = getDaysInMonth(month, year);
  var now = new Date();
  var results = { generated: 0, skipped: 0, edited: 0, final: 0, locked: 0, errors: [] };

  for (var day = 1; day <= totalDays; day++) {
    var dateObj = new Date(year, month - 1, day);
    var dateStr = formatDate(dateObj);
    var dayName = getDayName(dateObj);

    // Check existing prayer
    var existing = existingPrayers.find(function(p) {
      var pDate = new Date(p.Tanggal);
      return pDate.getDate() === day && pDate.getMonth() === (month - 1) && pDate.getFullYear() === year;
    });

    // Anti-timpa check
    if (existing) {
      if (existing.Locked === true || existing.Locked === 'TRUE') {
        results.locked++;
        continue;
      }
      if (existing.StatusDoa === 'Final' && skipFinal) {
        results.final++;
        continue;
      }
      if (existing.StatusDoa === 'Edited Manual' && skipEdited) {
        results.edited++;
        continue;
      }
      if (existing.StatusDoa !== 'Auto Draft' || !overwriteAutoDraft) {
        results.skipped++;
        continue;
      }
    }

    // === PRIORITAS 1: Hari Raya Kristen ===
    var hariKristen = allHariKhusus.filter(function(h) {
      var hDate = new Date(h.Tanggal);
      return hDate.getDate() === day && hDate.getMonth() === (month - 1) && hDate.getFullYear() === year &&
             h.Jenis === 'Kristen' && h.Status === 'Aktif';
    });

    if (hariKristen.length > 0) {
      var hk = hariKristen[0];
      var namaHari = hk.NamaHari || 'Hari Raya Kristen';
      var template = findTemplate(allTemplates, 'Hari Raya Kristen', hk.NamaHari) ||
                     findTemplate(allTemplates, 'Hari Raya Kristen', '');
      var isiDoa = template ? template.IsiTemplate : ('Mari kita bersyukur untuk ' + namaHari + '.');
      isiDoa = renderTemplate(isiDoa, dateObj, temaBulanIni, null, null);
      savePrayerEntry(existing, dateObj, dayName, month, year, unitMode, 'Hari Khusus', hk.HariID, namaHari, isiDoa, now);
      results.generated++;
      continue;
    }

    // === PRIORITAS 2-9: Kaldik Agenda ===
    var agendaHariIni = allKaldik.filter(function(k) {
      if (k.Status === 'Dibatalkan' || k.Status === 'Diarsipkan' || !k.MasukPokokDoa) return false;
      if (!k.TanggalMulai) return false;

      var start = new Date(k.TanggalMulai);
      // Match by scope + unit
      if (!isAgendaInUnitMode(k, unitMode, targetUnit)) return false;

      // Check if this agenda is relevant for this date
      // For multi-day: use rentang rules
      return isDateInAgenda(dateObj, k);
    });

    if (agendaHariIni.length > 0) {
      // Sort by priority
      agendaHariIni.sort(function(a, b) {
        var pa = PRIORITY_MAP[a.Kategori] || 9;
        var pb = PRIORITY_MAP[b.Kategori] || 9;
        return pa - pb;
      });

      var topAgenda = agendaHariIni[0];
      var allNames = agendaHariIni.map(function(a) { return a.NamaKegiatan; }).join(', ');

      // Build from template or catatan doa
      if (topAgenda.CatatanDoa && topAgenda.CatatanDoa.trim()) {
        var judul = 'Doa ' + topAgenda.NamaKegiatan;
        var isi = topAgenda.CatatanDoa;
        if (agendaHariIni.length > 1) {
          isi += '\n\nKiranya juga Tuhan memberkati: ' + allNames + '.';
        }
        isi = renderTemplate(isi, dateObj, temaBulanIni, null, topAgenda);
        savePrayerEntry(existing, dateObj, dayName, month, year, unitMode, 'Kaldik', topAgenda.KaldikID, judul, isi, now);
      } else {
        var tplKategori = findTemplate(allTemplates, topAgenda.Kategori || 'Umum', '') ||
                          findTemplate(allTemplates, 'Umum', '');
        var judul = 'Doa ' + topAgenda.NamaKegiatan;
        var isi = tplKategori ? tplKategori.IsiTemplate : 'Mari kita berdoa untuk ' + topAgenda.NamaKegiatan + '.';
        if (agendaHariIni.length > 1) {
          isi += '\n\nKiranya juga Tuhan memberkati: ' + allNames + '.';
        }
        isi = renderTemplate(isi, dateObj, temaBulanIni, null, topAgenda);
        savePrayerEntry(existing, dateObj, dayName, month, year, unitMode, 'Kaldik', topAgenda.KaldikID, judul, isi, now);
      }
      results.generated++;
      continue;
    }

    // === PRIORITAS 10: Ulang Tahun Karyawan ===
    var ultahHariIni = allKaryawan.filter(function(k) {
      if (!k.TanggalLahir) return false;
      var tgl = new Date(k.TanggalLahir);
      return tgl.getDate() === day && (tgl.getMonth() + 1) === month;
    });

    if (ultahHariIni.length > 0) {
      var names = ultahHariIni.map(function(k) { return k.NamaPanggilan || k.NamaLengkap; }).join(', ');
      var tpl = findTemplate(allTemplates, 'Ulang Tahun', '');
      var isi = tpl ? tpl.IsiTemplate : 'Mari kita berdoa untuk ' + names + ' yang berulang tahun.';
      isi = isi.replace(/\{nama\}/g, names);
      isi = renderTemplate(isi, dateObj, temaBulanIni, names, null);
      savePrayerEntry(existing, dateObj, dayName, month, year, unitMode, 'Ulang Tahun', null, 'Ulang Tahun: ' + names, isi, now);
      results.generated++;
      continue;
    }

    // === PRIORITAS 11: Template Sabtu ===
    if (dayName === 'Sabtu') {
      var tplSabtu = getRandomTemplate(allTemplates, 'Sabtu');
      var isi = tplSabtu ? tplSabtu.IsiTemplate : 'Mari kita menaikkan syukur untuk akhir pekan ini.';
      isi = renderTemplate(isi, dateObj, temaBulanIni, null, null);
      savePrayerEntry(existing, dateObj, dayName, month, year, unitMode, 'Template Sabtu', null, 'Doa Sabtu', isi, now);
      results.generated++;
      continue;
    }

    // === PRIORITAS 12: Template Minggu ===
    if (dayName === 'Minggu') {
      var tplMinggu = getRandomTemplate(allTemplates, 'Minggu');
      var isi = tplMinggu ? tplMinggu.IsiTemplate : 'Mari kita berdoa untuk ibadah di gereja masing-masing.';
      isi = renderTemplate(isi, dateObj, temaBulanIni, null, null);
      savePrayerEntry(existing, dateObj, dayName, month, year, unitMode, 'Template Minggu', null, 'Doa Minggu', isi, now);
      results.generated++;
      continue;
    }

    // === PRIORITAS 13: Doa Umum Harian ===
    var tplUmum = getRandomTemplate(allTemplates, 'Umum');
    var isi = tplUmum ? tplUmum.IsiTemplate : 'Mari kita berdoa untuk berkat dan penyertaan Tuhan hari ini.';
    isi = renderTemplate(isi, dateObj, temaBulanIni, null, null);
    savePrayerEntry(existing, dateObj, dayName, month, year, unitMode, 'Umum', null, 'Doa Harian', isi, now);
    results.generated++;
  }

  return {
    month: month,
    year: year,
    unitMode: unitMode,
    results: results,
    message: 'Generated: ' + results.generated + ', Skipped (edited): ' + results.edited + ', Final: ' + results.final + ', Locked: ' + results.locked + ', Errors: ' + results.errors.length
  };
}

/**
 * Regenerate satu tanggal spesifik
 */
function regeneratePrayerDate_(date, unitMode, options) {
  if (!date || !unitMode) throw new Error('Tanggal dan unitMode wajib diisi');

  var dateObj = new Date(date);
  var month = dateObj.getMonth() + 1;
  var year = dateObj.getFullYear();
  var day = dateObj.getDate();

  options = options || {};

  var existingPrayers = readSheet('POKOK_DOA').filter(function(p) {
    return p.Bulan == month && p.Tahun == year && p.UnitMode === unitMode;
  });

  var existing = existingPrayers.find(function(p) {
    var pDate = new Date(p.Tanggal);
    return pDate.getDate() === day && pDate.getMonth() === (month - 1) && pDate.getFullYear() === year;
  });

  // Anti-timpa
  if (existing) {
    if (existing.Locked === true || existing.Locked === 'TRUE') {
      throw new Error('Tanggal ini terkunci, tidak bisa diregenerate');
    }
    if (existing.StatusDoa === 'Final' && options.skipFinal !== false) {
      throw new Error('Tanggal ini sudah final');
    }
    if (existing.StatusDoa === 'Edited Manual' && options.skipEdited !== false) {
      throw new Error('Tanggal ini sudah diedit manual. Gunakan opsi force untuk menimpa.');
    }
  }

  // Re-run generate for this single day
  // We'll use a trick: generate full month but skip all except this day
  var forceOpts = {
    overwriteAutoDraft: true,
    skipEdited: false,
    skipFinal: false
  };
  // Run generate for the whole month with force for this one day
  // The anti-timpa will only apply to auto-drafts, so edited/final are still safe.

  var result = generatePrayer_(month, year, unitMode, forceOpts);

  writeChangeLog_('POKOK_DOA', date, 'REGENERATE_DATE', null, null, 'Regenerate tanggal ' + date + ' unitMode: ' + unitMode);

  return { date: date, unitMode: unitMode, results: result.results };
}

// ============================================================
// SAVE / UPDATE PRAYER
// ============================================================

function savePrayerEntry(existing, dateObj, dayName, month, year, unitMode, sumberData, sumberId, judul, isiDoa, now) {
  if (existing && existing.DoaID) {
    // Update existing
    updateRow('POKOK_DOA', 'DoaID', existing.DoaID, {
      SumberData: sumberData,
      SumberID: sumberId || null,
      Judul: judul || null,
      IsiDoa: isiDoa,
      StatusDoa: 'Auto Draft',
      EditMode: 'Auto',
      UpdatedAt: now
    });
  } else {
    // Create new
    var newDoa = {
      DoaID: generateId('DOA'),
      Tanggal: dateObj,
      Hari: dayName,
      Bulan: month,
      Tahun: year,
      UnitMode: unitMode,
      SumberData: sumberData,
      SumberID: sumberId || null,
      Judul: judul || null,
      IsiDoa: isiDoa,
      StatusDoa: 'Auto Draft',
      EditMode: 'Auto',
      Locked: false,
      CreatedAt: now,
      UpdatedAt: now
    };
    appendRow('POKOK_DOA', newDoa);
  }
}

function renderTemplate(templateText, dateObj, temaBulanIni, namaUltah, agendaItem) {
  var text = templateText || '';
  text = text.replace(/\{kegiatan\}/g, agendaItem ? (agendaItem.NamaKegiatan || '') : '');
  text = text.replace(/\{unit\}/g, agendaItem ? (agendaItem.Unit || '') : '');

  // Tema context
  if (temaBulanIni.length > 0) {
    var t = temaBulanIni[0];
    text = text.replace(/\{tema\}/g, t.Tema || '');
    text = text.replace(/\{ayat\}/g, t.Ayat || '');
  } else {
    text = text.replace(/\{tema\}/g, '');
    text = text.replace(/\{ayat\}/g, '');
  }

  text = text.replace(/\{bulan\}/g, getMonthName(dateObj.getMonth() + 1));
  text = text.replace(/\{tahun\}/g, String(dateObj.getFullYear()));

  return text;
}

