/**
 * Edit isi pokok doa secara manual
 */
function updatePrayer_(id, data) {
  if (!id) throw new Error('DoaID diperlukan');

  var updateData = {
    Judul: data.Judul || null,
    IsiDoa: data.IsiDoa || null,
    StatusDoa: 'Edited Manual',
    EditMode: 'Manual',
    UpdatedAt: new Date()
  };

  updateRow('POKOK_DOA', 'DoaID', id, updateData);

  writeChangeLog_('POKOK_DOA', id, 'UPDATE', null, 'Manual edit', 'Isi doa diedit manual');

  return { DoaID: id, message: 'Pokok doa diupdate' };
}

/**
 * Lock satu tanggal (tidak bisa ditimpa)
 */
function lockPrayer_(id) {
  if (!id) throw new Error('DoaID diperlukan');

  updateRow('POKOK_DOA', 'DoaID', id, {
    Locked: true,
    UpdatedAt: new Date()
  });

  writeChangeLog_('POKOK_DOA', id, 'LOCK', null, null, 'Terkunci');

  return { DoaID: id, message: 'Pokok doa dikunci' };
}

/**
 * Unlock
 */
function unlockPrayer_(id) {
  if (!id) throw new Error('DoaID diperlukan');

  updateRow('POKOK_DOA', 'DoaID', id, {
    Locked: false,
    UpdatedAt: new Date()
  });

  writeChangeLog_('POKOK_DOA', id, 'UNLOCK', null, null, 'Dibuka kunci');

  return { DoaID: id, message: 'Pokok doa dibuka kuncinya' };
}

/**
 * Finalize satu pokok doa
 */
function finalizePrayer_(id) {
  if (!id) throw new Error('DoaID diperlukan');

  updateRow('POKOK_DOA', 'DoaID', id, {
    StatusDoa: 'Final',
    Locked: true,
    UpdatedAt: new Date()
  });

  writeChangeLog_('POKOK_DOA', id, 'FINALIZE', null, null, 'Difinalkan');

  return { DoaID: id, message: 'Pokok doa difinalkan' };
}

/**
 * Finalize semua pokok doa dalam satu bulan
 */
function finalizePrayerMonth_(month, year, unitMode) {
  var prayers = readSheet('POKOK_DOA').filter(function(p) {
    return p.Bulan == month && p.Tahun == year &&
           (unitMode ? p.UnitMode === unitMode : true);
  });

  if (prayers.length === 0) throw new Error('Tidak ada pokok doa untuk bulan tersebut');

  var count = 0;
  prayers.forEach(function(p) {
    updateRow('POKOK_DOA', 'DoaID', p.DoaID, {
      StatusDoa: 'Final',
      Locked: true,
      UpdatedAt: new Date()
    });
    count++;
  });

  writeChangeLog_('POKOK_DOA', 'month-' + month + '-' + year, 'FINALIZE_MONTH', null, null, count + ' doa difinalkan');

  return { count: count, message: count + ' pokok doa difinalkan' };
}

/**
 * Get pokok doa by month/year/unitMode
 */
function getPokokDoa_(filters) {
  var allPrayers = readSheet('POKOK_DOA');

  if (filters) {
    if (filters.bulan && filters.bulan !== 'all') {
      allPrayers = allPrayers.filter(function(p) { return p.Bulan == filters.bulan; });
    }
    if (filters.tahun && filters.tahun !== 'all') {
      allPrayers = allPrayers.filter(function(p) { return p.Tahun == filters.tahun; });
    }
    if (filters.unitMode && filters.unitMode !== 'all') {
      allPrayers = allPrayers.filter(function(p) { return p.UnitMode === filters.unitMode; });
    }
  }

  return allPrayers;
}

