function findTemplate(allTemplates, jenis, kategori) {
  // Exact match first
  for (var i = 0; i < allTemplates.length; i++) {
    var t = allTemplates[i];
    if (t.JenisTemplate === jenis && t.Kategori === kategori && t.Status === 'Aktif') {
      return t;
    }
  }
  // Fallback: match jenis only
  for (var j = 0; j < allTemplates.length; j++) {
    var t2 = allTemplates[j];
    if (t2.JenisTemplate === jenis && t2.Status === 'Aktif') {
      return t2;
    }
  }
  return null;
}

function getRandomTemplate(allTemplates, jenis) {
  var filtered = allTemplates.filter(function(t) {
    return t.JenisTemplate === jenis && t.Status === 'Aktif';
  });
  if (filtered.length === 0) return null;
  var idx = Math.floor(Math.random() * filtered.length);
  return filtered[idx];
}

/**
 * Check apakah agenda termasuk dalam unit mode yang dipilih
 */
function isAgendaInUnitMode(agenda, unitMode, targetUnit) {
  if (unitMode === 'Gabungan Semua Unit') return true;
  if (unitMode === 'Universal') return agenda.UnitScope === 'UNIVERSAL';
  if (agenda.UnitScope === 'UNIVERSAL') return true;
  return agenda.Unit === targetUnit || (agenda.Unit && agenda.Unit.indexOf(targetUnit) > -1);
}

/**
 * Check apakah tanggal ini termasuk dalam rentang agenda
 * + aturan rentang: 1-2 hari=tanggal mulai; 3-7 hari=awal&akhir; >7 hari=awal&tengah&akhir
 */
function isDateInAgenda(dateObj, agenda) {
  if (!agenda.TanggalMulai) return false;
  var start = new Date(agenda.TanggalMulai);
  start.setHours(0, 0, 0, 0);

  var end = agenda.TanggalSelesai ? new Date(agenda.TanggalSelesai) : start;
  end.setHours(0, 0, 0, 0);

  var check = new Date(dateObj);
  check.setHours(0, 0, 0, 0);

  if (check < start || check > end) return false;

  var duration = Math.round((end - start) / (1000 * 60 * 60 * 24)) + 1;

  // 1-2 hari: start date
  if (duration <= 2) {
    return check.getTime() === start.getTime();
  }

  // 3-7 hari: start dan end
  if (duration <= 7) {
    return check.getTime() === start.getTime() || check.getTime() === end.getTime();
  }

  // >7 hari: start, mid, end
  var mid = new Date(Math.round((start.getTime() + end.getTime()) / 2));
  mid.setHours(0, 0, 0, 0);

  return check.getTime() === start.getTime() || check.getTime() === mid.getTime() || check.getTime() === end.getTime();
}

