/**
 * Inisialisasi semua sheet dan data awal
 * Dipanggil sekali saat setup
 */
function initSheets_() {
  var ss = getSpreadsheet();
  var sheetNames = [];
  
  // Buat sheet jika belum ada
  for (var configKey in SHEET_CONFIG) {
    var config = SHEET_CONFIG[configKey];
    var sheet = ss.getSheetByName(config.name);
    if (!sheet) {
      sheet = ss.insertSheet(config.name);
    }
    // Set headers
    sheet.getRange(1, 1, 1, config.headers.length)
         .setValues([config.headers])
         .setFontWeight('bold')
         .setBackground('#F3F4F6');
    sheetNames.push(config.name);
  }
  
  // Hapus Sheet1 jika ada
  var sheet1 = ss.getSheetByName('Sheet1');
  if (sheet1) {
    ss.deleteSheet(sheet1);
  }
  
  // Inisialisasi data SETTING
  initSettingData();
  
  // Inisialisasi data UNIT
  initUnitData();
  
  return {
    message: 'Semua sheet berhasil diinisialisasi',
    sheets: sheetNames
  };
}

/**
 * Inisialisasi data SETTING
 */
function initSettingData() {
  var existingSettings = readSheet('SETTING');
  
  // Detect corrupted data (header overwritten by data from previous bug)
  if (existingSettings.length > 0 && existingSettings[0].Key === undefined) {
    existingSettings = []; // Force re-init
  }
  
  if (existingSettings.length > 0) return; // Sudah ada data valid
  
  var defaultSettings = [
    ['APP_NAME', 'Kaldik & Pokok Doa Terpadu', 'Nama aplikasi'],
    ['APP_PIN', '123456', 'PIN akses admin'],
    ['TA_AKTIF', '2026-2027', 'Tahun ajaran aktif'],
    ['TIMEZONE', 'Asia/Jakarta', 'Zona waktu']
  ];
  writeSheet('SETTING', defaultSettings, true);
}

/**
