/**
 * Dapatkan spreadsheet object
 */
function getSpreadsheet() {
  var ss;
  if (SPREADSHEET_ID) {
    try {
      ss = SpreadsheetApp.openById(SPREADSHEET_ID);
    } catch(e) {
      // Spreadsheet was deleted or inaccessible, force re-init
      SPREADSHEET_ID = null;
      PropertiesService.getScriptProperties().deleteProperty('SPREADSHEET_ID');
    }
  }
  
  if (!ss) {
    try {
      ss = SpreadsheetApp.getActiveSpreadsheet();
    } catch(e) {
      ss = null;
    }
  }
  
  if (!ss || !ss.getId()) {
    // Auto-create spreadsheet for standalone scripts
    ss = SpreadsheetApp.create('Kaldik DB');
    SPREADSHEET_ID = ss.getId();
    PropertiesService.getScriptProperties().setProperty('SPREADSHEET_ID', ss.getId());
  } else if (!SPREADSHEET_ID && ss.getId()) {
    SPREADSHEET_ID = ss.getId();
    PropertiesService.getScriptProperties().setProperty('SPREADSHEET_ID', ss.getId());
  }
  
  return ss;
}

/**
 * Baca seluruh data sheet sebagai array of objects
 * @param {string} sheetKey - key di SHEET_CONFIG
 * @return {Array<Object>}
 */
function readSheet(sheetKey) {
  var config = SHEET_CONFIG[sheetKey];
  if (!config) throw new Error('Sheet config tidak ditemukan: ' + sheetKey);
  
  var ss = getSpreadsheet();
  var sheet = ss.getSheetByName(config.name);
  
  // Auto-init jika sheet belum ada
  if (!sheet) {
    initSheets_();
    sheet = ss.getSheetByName(config.name);
  }
  
  if (!sheet) return [];
  
  var data = sheet.getDataRange().getValues();
  if (data.length <= 1) return [];
  
  var headers = data[0];
  var rows = data.slice(1);
  
  return rows.map(function(row) {
    var obj = {};
    for (var i = 0; i < headers.length; i++) {
      obj[headers[i]] = row[i];
    }
    return obj;
  });
}

/**
 * Tulis data ke sheet (overwrite)
 * @param {string} sheetKey
 * @param {Array<Array>} rows - array of arrays
 * @param {boolean} includeHeaders - include header row
 */
function writeSheet(sheetKey, rows, includeHeaders) {
  var config = SHEET_CONFIG[sheetKey];
  if (!config) throw new Error('Sheet config tidak ditemukan: ' + sheetKey);
  
  var ss = getSpreadsheet();
  var sheet = ss.getSheetByName(config.name);
  if (!sheet) {
    sheet = ss.insertSheet(config.name);
  }
  
  // Clear existing data
  if (sheet.getLastRow() > 0) {
    sheet.clearContents();
  }
  
  // Prepare data
  var data = [];
  if (includeHeaders !== false) {
    data.push(config.headers);
  }
  data = data.concat(rows);
  
  if (data.length > 0) {
    sheet.getRange(1, 1, data.length, data[0].length).setValues(data);
    // Style header
    sheet.getRange(1, 1, 1, config.headers.length)
         .setFontWeight('bold')
         .setBackground('#F3F4F6');
  }
  
  return true;
}

/**
 * Append baris ke sheet
 * @param {string} sheetKey
 * @param {Object} rowObj - single row as object
 * @return {number} row index
 */
function appendRow(sheetKey, rowObj) {
  var config = SHEET_CONFIG[sheetKey];
  if (!config) throw new Error('Sheet config tidak ditemukan: ' + sheetKey);
  
  var ss = getSpreadsheet();
  var sheet = ss.getSheetByName(config.name);
  if (!sheet) {
    sheet = ss.insertSheet(config.name);
    sheet.getRange(1, 1, 1, config.headers.length)
         .setValues([config.headers])
         .setFontWeight('bold')
         .setBackground('#F3F4F6');
  }
  
  var rowArray = [];
  for (var i = 0; i < config.headers.length; i++) {
    var header = config.headers[i];
    var value = rowObj[header] !== undefined ? rowObj[header] : null;
    rowArray.push(value);
  }
  
  sheet.appendRow(rowArray);
  return sheet.getLastRow();
}

/**
 * Update baris tertentu di sheet
 * @param {string} sheetKey
 * @param {string} idField - nama kolom ID (misal: 'KaldikID')
 * @param {string} id - nilai ID
 * @param {Object} data - data update
 */
function updateRow(sheetKey, idField, id, data) {
  var config = SHEET_CONFIG[sheetKey];
  if (!config) throw new Error('Sheet config tidak ditemukan: ' + sheetKey);
  
  var ss = getSpreadsheet();
  var sheet = ss.getSheetByName(config.name);
  if (!sheet) throw new Error('Sheet tidak ditemukan: ' + config.name);
  
  var allData = sheet.getDataRange().getValues();
  if (allData.length <= 1) throw new Error('Tidak ada data di sheet');
  
  var headers = allData[0];
  var idColIndex = headers.indexOf(idField);
  if (idColIndex === -1) throw new Error('Kolom ID tidak ditemukan: ' + idField);
  
  for (var r = 1; r < allData.length; r++) {
    if (allData[r][idColIndex] == id) {
      // Update row
      for (var key in data) {
        var colIndex = headers.indexOf(key);
        if (colIndex >= 0) {
          sheet.getRange(r + 1, colIndex + 1).setValue(data[key]);
        }
      }
      return true;
    }
  }
  
  throw new Error('Record tidak ditemukan: ' + id);
}

/**
 * Hapus baris berdasarkan ID
 */
function deleteRow(sheetKey, idField, id) {
  var config = SHEET_CONFIG[sheetKey];
  var ss = getSpreadsheet();
  var sheet = ss.getSheetByName(config.name);
  if (!sheet) return false;
  
  var allData = sheet.getDataRange().getValues();
  var idColIndex = allData[0].indexOf(idField);
  if (idColIndex === -1) return false;
  
  for (var r = 1; r < allData.length; r++) {
    if (allData[r][idColIndex] == id) {
      sheet.deleteRow(r + 1);
      return true;
    }
  }
  
  return false;
}

