/**
 * Get app info (untuk frontend)
 */
function getAppInfo_() {
  var settings = readSheet('SETTING');
  var info = {};
  for (var i = 0; i < settings.length; i++) {
    info[settings[i].Key] = settings[i].Value;
  }
  return info;
}

/**
 * Get specific setting
 */
function getSetting_(key) {
  return { key: key, value: getSetting(key) };
}

/**
 * Update setting
 */
function updateSetting_(key, value) {
  var allSettings = readSheet('SETTING');
  var found = false;
  
  for (var i = 0; i < allSettings.length; i++) {
    if (allSettings[i].Key === key) {
      allSettings[i].Value = value;
      found = true;
      break;
    }
  }
  
  if (!found) {
    allSettings.push({ Key: key, Value: value, Description: '' });
  }
  
  // Rewrite
  var rows = allSettings.map(function(s) {
    return [s.Key, s.Value, s.Description];
  });
  writeSheet('SETTING', rows, true);
  
  return { key: key, value: value };
}

