/**
 * Get dashboard summary
 */
function getDashboard_(filters) {
  var now = new Date();
  var currentMonth = filters ? (filters.bulan || (now.getMonth() + 1)) : (now.getMonth() + 1);
  var currentYear = filters ? (filters.tahun || now.getFullYear()) : now.getFullYear();
  
  var allKaldik = readSheet('KALDIK_NORMALIZED');
  var allPerluCek = readSheet('PERLU_CEK');
  var allTanpaTanggal = readSheet('CATATAN_TANPA_TANGGAL');
  var allPokokDoa = readSheet('POKOK_DOA');
  
  // Filter agenda bulan ini (status bukan Dibatalkan/Diarsipkan)
  var agendaBulanIni = allKaldik.filter(function(a) {
    return a.Bulan == currentMonth && a.Tahun == currentYear &&
           a.Status !== 'Dibatalkan' && a.Status !== 'Diarsipkan';
  });
  
  // Count per unit scope
  var countUniversal = agendaBulanIni.filter(function(a) { return a.UnitScope === 'UNIVERSAL'; }).length;
  var countTK = agendaBulanIni.filter(function(a) {
    return a.UnitScope === 'UNIT' && a.Unit === 'U002';
  }).length;
  var countSD = agendaBulanIni.filter(function(a) {
    return a.UnitScope === 'UNIT' && a.Unit === 'U003';
  }).length;
  var countSMP = agendaBulanIni.filter(function(a) {
    return a.UnitScope === 'UNIT' && a.Unit === 'U004';
  }).length;
  var countMNG = agendaBulanIni.filter(function(a) {
    return a.UnitScope === 'UNIT' && a.Unit === 'U005';
  }).length;
  var countTBI = agendaBulanIni.filter(function(a) {
    return a.UnitScope === 'UNIT' && a.Unit === 'U006';
  }).length;
  var countRTS = agendaBulanIni.filter(function(a) {
    return a.UnitScope === 'UNIT' && a.Unit === 'U007';
  }).length;
  
  // Perlu cek (status = Perlu Cek)
  var perluCekCount = allPerluCek.filter(function(c) {
    return c.Status === 'Perlu Cek';
  }).length;
  
  // Tanpa tanggal (status = Belum Diproses)
  var tanpaTanggalCount = allTanpaTanggal.filter(function(t) {
    return t.Status === 'Belum Diproses';
  }).length;
  
  // Pokok Doa bulan ini
  var pokokDoaBulanIni = allPokokDoa.filter(function(d) {
    return d.Bulan == currentMonth && d.Tahun == currentYear;
  });
  var pokokDoaDraft = pokokDoaBulanIni.filter(function(d) {
    return d.StatusDoa === 'Auto Draft';
  }).length;
  var pokokDoaFinal = pokokDoaBulanIni.filter(function(d) {
    return d.StatusDoa === 'Final';
  }).length;
  
  // Tema bulan aktif
  var tema = readSheet('TEMA_BULANAN').filter(function(t) {
    return t.Bulan == currentMonth && t.Tahun == currentYear;
  });
  
  // Ulang tahun bulan ini
  var karyawan = readSheet('KARYAWAN');
  var ultahBulanIni = karyawan.filter(function(k) {
    if (!k.TanggalLahir) return false;
    var tgl = new Date(k.TanggalLahir);
    return (tgl.getMonth() + 1) == currentMonth;
  });
  
  return {
    bulan: currentMonth,
    tahun: currentYear,
    namaBulan: getMonthName(currentMonth),
    temaAktif: tema.length > 0 ? tema[0].Tema : null,
    totalAgenda: agendaBulanIni.length,
    countUniversal: countUniversal,
    countTK: countTK,
    countSD: countSD,
    countSMP: countSMP,
    countMNG: countMNG,
    countTBI: countTBI,
    countRTS: countRTS,
    perluCek: perluCekCount,
    tanpaTanggal: tanpaTanggalCount,
    pokokDoaDraft: pokokDoaDraft,
    pokokDoaFinal: pokokDoaFinal,
    ultahBulanIni: ultahBulanIni.length
  };
}

