/**
 * getInitialData — Endpoint tunggal untuk load data awal aplikasi.
 * Menggantikan getAppInfo + getUnits yang terpisah.
 * Return seluruh data initial yang dibutuhkan frontend.
 * Cache: 6 jam
 */
function getInitialData_() {
  var cacheKey = 'APP_INIT';
  var cached = getCacheJson(cacheKey);
  if (cached) return cached;

  var now = new Date();
  var settings = readSheet('SETTING');
  var info = {};
  for (var i = 0; i < settings.length; i++) {
    info[settings[i].Key] = settings[i].Value;
  }

  var data = {
    appInfo: info,
    units: readSheet('UNIT'),
    settings: info,
    activeTA: info.TA_AKTIF || '2026-2027',
    currentMonth: now.getMonth() + 1,
    currentYear: now.getFullYear()
  };

  setCacheJson(cacheKey, data, 21600); // 6 jam
  return data;
}

/**
 * getKaldikCalendarPayload — Endpoint gabungan untuk render kalender Kaldik.
 * Return agendas + hariKhusus dalam satu panggilan.
 * Frontend tidak perlu getKaldik → render → getHariKhusus → render lagi.
 * Cache: 5 menit per kombinasi bulan/tahun/unit
 */
function getKaldikCalendarPayload_(filters) {
  filters = filters || {};
  var bulan = filters.bulan || (new Date().getMonth() + 1);
  var tahun = filters.tahun || new Date().getFullYear();
  var unit = filters.unit || 'all';

  var cacheKey = 'KALDIK_MONTH_' + tahun + '_' + String(bulan).padStart(2, '0') + '_' + unit;
  var cached = getCacheJson(cacheKey);
  if (cached) return cached;

  var agendas = getKaldik_(filters);
  var hariKhusus = getHariKhusus_({
    month: bulan,
    year: tahun
  });

  var data = {
    agendas: agendas,
    hariKhusus: hariKhusus,
    summary: {
      total: agendas.length,
      bulan: bulan,
      tahun: tahun
    }
  };

  setCacheJson(cacheKey, data, 300); // 5 menit
  return data;
}

/**
 * Clear related caches when data changes.
 * Called after: add/edit/import Kaldik, add/edit Karyawan, edit Tema, edit Hari Khusus.
 */
function clearRelatedCaches_(entity, filters) {
  try {
    var cache = CacheService.getScriptCache();
    // Clear APP_INIT
    cache.remove('APP_INIT');
    cache.remove('UNITS');
    cache.remove('SETTING');
    cache.remove('KARYAWAN');
    cache.remove('BIRTHDAY_MONTH');

    // Clear KALDIK_MONTH cache untuk bulan terkait
    if (entity === 'KALDIK' || entity === 'HARI_KHUSUS') {
      var bulan = filters && filters.bulan ? filters.bulan : (new Date().getMonth() + 1);
      var tahun = filters && filters.tahun ? filters.tahun : new Date().getFullYear();
      // Clear all unit-specific caches for this month/year combo
      var allUnits = ['all', 'U001', 'U002', 'U003', 'U004', 'U005', 'U006', 'U007'];
      for (var i = 0; i < allUnits.length; i++) {
        var key = 'KALDIK_MONTH_' + tahun + '_' + String(bulan).padStart(2, '0') + '_' + allUnits[i];
        cache.remove(key);
      }
    }
  } catch (e) {
    // Silent fail — cache clearing is best-effort
  }
}

/**
 * Unit code → readable name mapping.
 * DEPRECATED — use global UNIT_CODE_MAP & normalizeUnit() from Utils.gs.
 * Kept as alias for backward compatibility.
 */
var UNIT_CODE_MAP_ = UNIT_CODE_MAP;

/**
 * Normalize unit value to readable name (U002 → TK, etc.)
 * DEPRECATED — use global normalizeUnit() from Utils.gs.
 */
function normalizeUnit_(unitValue) {
  return normalizeUnit(unitValue);
}

/**
 * Normalize month value: name → number ("Juli" → 7, 7 → 7)
 */
var MONTH_NAME_TO_NUMBER_ = {
  'JANUARI': 1, 'FEBRUARI': 2, 'MARET': 3, 'APRIL': 4,
  'MEI': 5, 'JUNI': 6, 'JULI': 7, 'AGUSTUS': 8,
  'SEPTEMBER': 9, 'OKTOBER': 10, 'NOVEMBER': 11, 'DESEMBER': 12
};

function normalizeMonth_(value) {
  if (value === null || value === undefined) return null;
  if (typeof value === 'number') return value;
  var str = String(value).trim();
  var num = Number(str);
  if (!isNaN(num) && num >= 1 && num <= 12) return num;
  return MONTH_NAME_TO_NUMBER_[str.toUpperCase()] || null;
}

/**
 * Get Kaldik dengan filter
 */
function getKaldik_(filters) {
  var allKaldik = readSheet('KALDIK_NORMALIZED');
  
  // === Normalize every row: Unit & Bulan ===
  allKaldik.forEach(function(k) {
    k.UnitRaw = k.Unit;
    k.Unit = normalizeUnit_(k.Unit);
    k.Bulan = normalizeMonth_(k.Bulan);
    if (k.Tahun && typeof k.Tahun !== 'number') {
      k.Tahun = parseInt(k.Tahun) || k.Tahun;
    }
  });
  
  // Normalize filter values
  var filterUnit = filters.unit ? normalizeUnit_(filters.unit) : null;
  var filterBulan = normalizeMonth_(filters.bulan);
  var filterTahun = filters.tahun && filters.tahun !== 'all' ? parseInt(filters.tahun) : null;
  
  // Filter by selected unit with scope logic
  if (filters.unit && filters.unit !== 'all') {
    allKaldik = allKaldik.filter(function(k) {
      // UNIVERSAL always shown
      if (k.UnitScope === 'UNIVERSAL') return true;
      // UNIT: match normalized unit
      if (k.UnitScope === 'UNIT' && k.Unit === filterUnit) return true;
      // MULTI_UNIT: contains the unit ID or normalized name
      if (k.UnitScope === 'MULTI_UNIT' && k.UnitRaw) {
        var rawUpper = String(k.UnitRaw).toUpperCase();
        if (rawUpper.indexOf(filters.unit.toUpperCase()) > -1) return true;
        if (rawUpper.indexOf(filterUnit.toUpperCase()) > -1) return true;
      }
      return false;
    });
  }
  
  // Filter by tahun ajaran
  if (filters.tahunAjaran && filters.tahunAjaran !== 'all') {
    allKaldik = allKaldik.filter(function(k) { return k.TahunAjaran === filters.tahunAjaran; });
  }
  
  // Filter by semester
  if (filters.semester && filters.semester !== 'all') {
    allKaldik = allKaldik.filter(function(k) { return k.Semester == filters.semester; });
  }
  
  // Filter by bulan
  if (filterBulan !== null) {
    allKaldik = allKaldik.filter(function(k) { return k.Bulan == filterBulan; });
  }
  
  // Filter by tahun
  if (filterTahun !== null) {
    allKaldik = allKaldik.filter(function(k) { return k.Tahun == filterTahun; });
  }
  
  // Filter by kategori
  if (filters.kategori && filters.kategori !== 'all') {
    allKaldik = allKaldik.filter(function(k) { return k.Kategori === filters.kategori; });
  }
  
  // Filter by status
  if (filters.status && filters.status !== 'all') {
    allKaldik = allKaldik.filter(function(k) { return k.Status === filters.status; });
  }
  
  // Filter by masuk pokok doa
  if (filters.masukPokokDoa === 'true') {
    allKaldik = allKaldik.filter(function(k) { return k.MasukPokokDoa === true || k.MasukPokokDoa === 'TRUE'; });
  }
  
  // === Deduplicate ===
  allKaldik = dedupeAgendaRows_(allKaldik);
  
  return allKaldik;
}

/**
 * Normalize text for comparison (lowercase, collapse whitespace)
 */
function normalizeText_(text) {
  return String(text || '').trim().toLowerCase().replace(/\s+/g, ' ');
}

/**
 * Create a unique key for deduplication
 */
function makeAgendaUniqueKey_(row) {
  var tanggalMulai = '';
  var tanggalSelesai = '';
  try {
    if (row.TanggalMulai instanceof Date) {
      tanggalMulai = Utilities.formatDate(row.TanggalMulai, Session.getScriptTimeZone(), 'yyyy-MM-dd');
    } else if (row.TanggalMulai) {
      tanggalMulai = String(row.TanggalMulai).trim();
    }
    if (row.TanggalSelesai instanceof Date) {
      tanggalSelesai = Utilities.formatDate(row.TanggalSelesai, Session.getScriptTimeZone(), 'yyyy-MM-dd');
    } else if (row.TanggalSelesai) {
      tanggalSelesai = String(row.TanggalSelesai).trim();
    }
  } catch (e) {
    tanggalMulai = String(row.TanggalMulai || '').trim();
    tanggalSelesai = String(row.TanggalSelesai || '').trim();
  }
  // Use normalized unit so U002 and TK are treated as same
  var normalUnit = normalizeUnit_(row.Unit || row.UnitRaw);
  return [
    row.TahunAjaran || '',
    normalUnit,
    row.UnitScope || '',
    tanggalMulai,
    tanggalSelesai || tanggalMulai,
    normalizeText_(row.NamaKegiatan)
  ].join('|');
}

/**
 * Deduplicate agenda rows by unique key.
 * Filters out soft-deleted rows (Diarsipkan/Duplikat/Dibatalkan).
 * Keeps only the first row for each unique key.
 */
function dedupeAgendaRows_(rows) {
  var seen = {};
  var result = [];
  rows.forEach(function(row) {
    var status = String(row.Status || '').toLowerCase();
    // Skip soft-deleted / archived rows
    if (status === 'diarsipkan' || status === 'duplikat' || status === 'dibatalkan') return;
    var key = makeAgendaUniqueKey_(row);
    if (!seen[key]) {
      seen[key] = true;
      result.push(row);
    }
  });
  return result;
}

/**
 * Scan KALDIK_NORMALIZED for duplicates and return report
 */
function scanDuplicates_() {
  var allRows = readSheet('KALDIK_NORMALIZED');
  var keyMap = {};
  var duplicateGroups = [];
  var seenGroupKeys = {};

  allRows.forEach(function(row) {
    var status = String(row.Status || '').toLowerCase();
    if (status === 'diarsipkan' || status === 'duplikat' || status === 'dibatalkan') return;
    var key = makeAgendaUniqueKey_(row);
    if (!keyMap[key]) {
      keyMap[key] = [];
    }
    keyMap[key].push(row);
  });

  var duplicateKeys = Object.keys(keyMap).filter(function(k) { return keyMap[k].length > 1; });

  if (duplicateKeys.length === 0) {
    return {
      success: true,
      duplicateCount: 0,
      duplicateGroups: [],
      message: 'Tidak ditemukan data duplikat.'
    };
  }

  duplicateKeys.forEach(function(key) {
    var rows = keyMap[key];
    duplicateGroups.push({
      uniqueKey: key,
      count: rows.length,
      name: rows[0].NamaKegiatan || '',
      unit: rows[0].Unit || '',
      tanggalMulai: rows[0].TanggalMulai || '',
      tanggalSelesai: rows[0].TanggalSelesai || '',
      kaldikIds: rows.map(function(r) { return r.KaldikID || ''; })
    });
  });

  return {
    success: true,
    duplicateCount: duplicateGroups.length,
    duplicateRows: duplicateGroups.reduce(function(sum, g) { return sum + g.count; }, 0),
    duplicateGroups: duplicateGroups,
    message: 'Ditemukan ' + duplicateGroups.length + ' grup duplikat (' + duplicateGroups.reduce(function(sum, g) { return sum + g.count; }, 0) + ' baris).'
  };
}

/**
 * Archive duplicate rows: soft-delete by setting Status = 'Duplikat'
 */
function archiveDuplicates_(kaldikIdsToArchive) {
  if (!kaldikIdsToArchive || kaldikIdsToArchive.length === 0) {
    return { success: false, message: 'Tidak ada ID yang diberikan.' };
  }

  var allRows = readSheet('KALDIK_NORMALIZED');
  var idSet = {};
  kaldikIdsToArchive.forEach(function(id) { idSet[id] = true; });

  var updatedCount = 0;
  allRows.forEach(function(row) {
    if (idSet[row.KaldikID] && String(row.Status || '').toLowerCase() !== 'duplikat') {
      row.Status = 'Duplikat';
      row.UpdatedAt = new Date();
      updatedCount++;
    }
  });

  if (updatedCount === 0) {
    return { success: true, message: 'Tidak ada baris yang perlu diarsipkan (sudah Duplikat atau ID tidak ditemukan).', archived: 0 };
  }

  // Write back entire sheet (batch update)
  var config = SHEET_CONFIG['KALDIK_NORMALIZED'];
  var ss = getSpreadsheet();
  var sheet = ss.getSheetByName(config.name);
  if (!sheet) return { success: false, message: 'Sheet KALDIK_NORMALIZED tidak ditemukan.' };

  var headers = config.headers;
  var data = [headers];
  allRows.forEach(function(row) {
    var rowArr = headers.map(function(h) { return row[h] !== undefined ? row[h] : ''; });
    data.push(rowArr);
  });

  sheet.getRange(1, 1, data.length, data[0].length).setValues(data);

  // Write CHANGE_LOG
  writeChangeLog_(
    'KALDIK',
    'DEDUPE_' + generateId('DUP'),
    'BULK_UPDATE',
    null,
    JSON.stringify({ archivedCount: updatedCount, ids: kaldikIdsToArchive }),
    'Arsipkan ' + updatedCount + ' baris duplikat agenda.'
  );

  // Clear cache after dedupe
  clearRelatedCaches_('KALDIK');

  return {
    success: true,
    archived: updatedCount,
    message: 'Berhasil mengarsipkan ' + updatedCount + ' baris duplikat.'
  };
}

/**
 * Fix duplicate/empty KaldikIDs — assign new unique IDs
 */
function fixDuplicateKaldikIds_() {
  var allRows = readSheet('KALDIK_NORMALIZED');
  var idCount = {};
  var needsFix = [];
  var now = new Date();

  // Count KaldikID occurrences
  allRows.forEach(function(row, index) {
    var id = row.KaldikID || '';
    if (!id || id.trim() === '') {
      needsFix.push({ index: index, row: row, reason: 'empty' });
    } else {
      if (!idCount[id]) idCount[id] = [];
      idCount[id].push(index);
    }
  });

  // Find duplicate IDs
  Object.keys(idCount).forEach(function(id) {
    if (idCount[id].length > 1) {
      // Keep first, fix the rest
      for (var j = 1; j < idCount[id].length; j++) {
        needsFix.push({ index: idCount[id][j], row: allRows[idCount[id][j]], reason: 'duplicate' });
      }
    }
  });

  if (needsFix.length === 0) {
    return {
      success: true,
      fixed: 0,
      message: 'Semua KaldikID sudah unik. Tidak ada yang perlu diperbaiki.'
    };
  }

  // Generate new unique IDs
  var basePrefix = 'KAL';
  var counter = 0;
  var existingIds = {};
  allRows.forEach(function(row) { if (row.KaldikID) existingIds[row.KaldikID] = true; });

  function generateNewId() {
    var ts = Utilities.formatDate(now, Session.getScriptTimeZone(), 'yyyyMMdd');
    var unique;
    do {
      counter++;
      unique = basePrefix + '-' + ts + '-' + String(counter).padStart(4, '0');
    } while (existingIds[unique]);
    existingIds[unique] = true;
    return unique;
  }

  needsFix.forEach(function(fix) {
    var newId = generateNewId();
    fix.row.KaldikID = newId;
    fix.row.UpdatedAt = now;
    fix.newId = newId;
  });

  // Write back entire sheet
  var config = SHEET_CONFIG['KALDIK_NORMALIZED'];
  var ss = getSpreadsheet();
  var sheet = ss.getSheetByName(config.name);
  if (!sheet) return { success: false, message: 'Sheet KALDIK_NORMALIZED tidak ditemukan.' };

  var headers = config.headers;
  var data = [headers];
  allRows.forEach(function(row) {
    var rowArr = headers.map(function(h) { return row[h] !== undefined ? row[h] : ''; });
    data.push(rowArr);
  });

  sheet.getRange(1, 1, data.length, data[0].length).setValues(data);

  // Write CHANGE_LOG
  writeChangeLog_(
    'KALDIK',
    'IDFIX_' + generateId('FIX'),
    'BULK_UPDATE',
    null,
    JSON.stringify({ fixed: needsFix.length, emptyCount: needsFix.filter(function(f) { return f.reason === 'empty'; }).length, dupCount: needsFix.filter(function(f) { return f.reason === 'duplicate'; }).length }),
    'Perbaiki ' + needsFix.length + ' KaldikID (kosong: ' + needsFix.filter(function(f) { return f.reason === 'empty'; }).length + ', duplikat: ' + needsFix.filter(function(f) { return f.reason === 'duplicate'; }).length + ').'
  );

  return {
    success: true,
    fixed: needsFix.length,
    emptyCount: needsFix.filter(function(f) { return f.reason === 'empty'; }).length,
    duplicateCount: needsFix.filter(function(f) { return f.reason === 'duplicate'; }).length,
    message: 'Berhasil memperbaiki ' + needsFix.length + ' KaldikID.'
  };
}

/**
 * Safe wrapper untuk getKaldik — return selalu {status, data/message} 
 * (bypass api() untuk menghindari serialization issues)
 */
function getKaldikV2(filters) {
  try {
    var result = getKaldik_(filters || {});
    return {
      status: 'success',
      data: result,
      message: 'OK (' + result.length + ' rows)',
      timestamp: new Date().toISOString()
    };
  } catch (e) {
    return {
      status: 'error',
      data: [],
      message: e.message || String(e),
      timestamp: new Date().toISOString()
    };
  }
}

