/**
 * Add Kaldik baru
 */
function addKaldik_(data) {
  var kaldikId = generateId('KAL');
  var now = new Date();
  
  var newRecord = {
    KaldikID: kaldikId,
    TahunAjaran: data.TahunAjaran || getSetting('TA_AKTIF') || '2026-2027',
    Semester: data.Semester || getSemester(data.Bulan || (new Date().getMonth() + 1)),
    Bulan: data.Bulan,
    Tahun: data.Tahun,
    Unit: data.Unit || 'U001',
    UnitScope: data.UnitScope || 'UNIT',
    TanggalMulai: data.TanggalMulai ? new Date(data.TanggalMulai) : null,
    TanggalSelesai: data.TanggalSelesai ? new Date(data.TanggalSelesai) : null,
    TanggalMentah: data.TanggalMentah || null,
    NamaKegiatan: data.NamaKegiatan,
    Kategori: data.Kategori || 'Umum',
    PrioritasDoa: data.PrioritasDoa || 3,
    MasukPokokDoa: data.MasukPokokDoa !== undefined ? data.MasukPokokDoa : true,
    CatatanDoa: data.CatatanDoa || null,
    Status: data.Status || 'Draft',
    SumberData: data.SumberData || 'Manual',
    CreatedAt: now,
    UpdatedAt: now
  };
  
  appendRow('KALDIK_NORMALIZED', newRecord);
  
  // Clear cache
  clearRelatedCaches_('KALDIK', { bulan: newRecord.Bulan, tahun: newRecord.Tahun });
  
  return { KaldikID: kaldikId };
}

/**
 * Bulk add agenda — satu judul kegiatan, banyak tanggal terpisah
 */
function bulkAddAgenda_(data) {
  // === Validate required fields ===
  if (!data.namaKegiatan || !String(data.namaKegiatan).trim()) {
    return { success: false, message: 'Nama kegiatan wajib diisi' };
  }
  if (!data.unit) {
    return { success: false, message: 'Unit wajib dipilih' };
  }
  if (!data.dates || !Array.isArray(data.dates) || data.dates.length === 0) {
    return { success: false, message: 'Minimal 1 tanggal harus dipilih' };
  }

  var namaKegiatan = String(data.namaKegiatan).trim();
  var unit = data.unit;
  var unitScope = data.unitScope || 'UNIT';
  var durationDays = parseInt(data.durationDays) || 1;
  var duplicateMode = data.duplicateMode || 'skip';
  var now = new Date();

  /**
   * Parse date string to ISO yyyy-mm-dd. Accepts:
   * - "yyyy-mm-dd", "dd mmmm yyyy", "yyyy/mm/dd"
   */
  function toIsoDate(d) {
    if (!d) return null;
    var s = String(d).trim();
    // Already ISO: "yyyy-mm-dd"
    if (/^\d{4}-\d{2}-\d{2}$/.test(s)) return s;
    // Try new Date fallback
    var dt = new Date(s);
    if (!isNaN(dt.getTime())) {
      var y = dt.getFullYear();
      var m = String(dt.getMonth() + 1).padStart(2, '0');
      var day = String(dt.getDate()).padStart(2, '0');
      return y + '-' + m + '-' + day;
    }
    return null;
  }

  // === Normalize & deduplicate dates ===
  var seenDates = {};
  var normalizedDates = [];
  data.dates.forEach(function(d) {
    var isoDate = toIsoDate(d);
    if (!isoDate) return;
    if (seenDates[isoDate]) return; // skip duplicate in input
    seenDates[isoDate] = true;
    normalizedDates.push(isoDate);
  });

  if (normalizedDates.length === 0) {
    return { success: false, message: 'Tidak ada tanggal valid. Format: yyyy-mm-dd atau dd mmmm yyyy' };
  }

  // Sort dates chronologically
  normalizedDates.sort();

  // === Check existing duplicates in sheet ===
  var existingRecords = readSheet('KALDIK_NORMALIZED');
  var existingMap = {};
  existingRecords.forEach(function(r) {
    if (!r.TanggalMulai) return;
    var existingDate = toIsoDate(r.TanggalMulai);
    if (!existingDate) return;
    var key = existingDate + '|' + (r.Unit || '') + '|' + (r.NamaKegiatan || '');
    existingMap[key] = true;
  });

  // === Build records, skip duplicates per mode ===
  var toInsert = [];
  var skippedCount = 0;
  var skippedDates = [];

  normalizedDates.forEach(function(isoDate) {
    var parts = isoDate.split('-');
    var y = parseInt(parts[0]), m = parseInt(parts[1]), d = parseInt(parts[2]);
    var sd = new Date(y, m - 1, d);
    var endDate = new Date(sd);
    if (durationDays > 1) {
      endDate.setDate(endDate.getDate() + durationDays - 1);
    }

    var checkKey = isoDate + '|' + unit + '|' + namaKegiatan;
    if (existingMap[checkKey]) {
      if (duplicateMode === 'skip') {
        skippedCount++;
        skippedDates.push(isoDate);
        return;
      }
      // 'force' mode: tetap insert
    }

    var kaldikId = generateId('KAL');
    var bulanMonth = sd.getMonth() + 1;
    var semester = bulanMonth >= 7 ? 1 : 2;

    var record = {
      KaldikID: kaldikId,
      TahunAjaran: data.tahunAjaran || '2026-2027',
      Semester: data.semester || semester,
      Bulan: bulanMonth,
      Tahun: sd.getFullYear(),
      Unit: unit,
      UnitScope: unitScope,
      TanggalMulai: sd,
      TanggalSelesai: endDate,
      TanggalMentah: isoDate,
      NamaKegiatan: namaKegiatan,
      Kategori: data.kategori || 'Umum',
      PrioritasDoa: data.prioritasDoa || 3,
      MasukPokokDoa: data.masukPokokDoa !== undefined ? data.masukPokokDoa : true,
      CatatanDoa: data.catatanDoa || null,
      Status: data.status || 'Valid',
      SumberData: 'Manual',
      CreatedAt: now,
      UpdatedAt: now
    };

    toInsert.push(record);
  });

  // === Write all records ===
  if (toInsert.length === 0) {
    return {
      success: true,
      inserted: 0,
      skippedDuplicate: skippedCount,
      skippedDates: skippedDates,
      message: 'Tidak ada agenda baru yang ditambahkan. ' + skippedCount + ' agenda sudah ada (dilewati).'
    };
  }

  toInsert.forEach(function(rec) {
    appendRow('KALDIK_NORMALIZED', rec);
  });

  // === Write CHANGE_LOG ===
  writeChangeLog_(
    'KALDIK',
    'BULK_' + generateId('BLK'),
    'BULK_INSERT',
    null,
    JSON.stringify({ nama: namaKegiatan, unit: unit, count: toInsert.length }),
    'Bulk tambah agenda "' + namaKegiatan + '" untuk ' + toInsert.length + ' tanggal. Inserted: ' + toInsert.length + ', skipped: ' + skippedCount + '.'
  );

  // Clear cache
  if (toInsert.length > 0) {
    var firstRec = toInsert[0];
    clearRelatedCaches_('KALDIK', { bulan: firstRec.Bulan, tahun: firstRec.Tahun });
  }

  return {
    success: true,
    inserted: toInsert.length,
    skippedDuplicate: skippedCount,
    skippedDates: skippedDates,
    message: 'Berhasil menambahkan ' + toInsert.length + ' agenda.' + (skippedCount > 0 ? ' ' + skippedCount + ' agenda duplikat dilewati.' : '')
  };
}

/**
 * Update Kaldik
 */
function updateKaldik_(id, data) {
  if (!id) throw new Error('KaldikID diperlukan');
  
  data.UpdatedAt = new Date();
  updateRow('KALDIK_NORMALIZED', 'KaldikID', id, data);
  
  // Clear cache
  if (data.Bulan || data.Tahun) {
    clearRelatedCaches_('KALDIK', { bulan: data.Bulan, tahun: data.Tahun });
  } else {
    clearRelatedCaches_('KALDIK');
  }
  
  return { KaldikID: id };
}

