/**
 * Konversi catatan tanpa tanggal menjadi agenda Kaldik
 */
function convertNoteToAgenda_(id, agendaData) {
  if (!id) throw new Error('NoteID diperlukan');

  var notes = readSheet('CATATAN_TANPA_TANGGAL');
  var noteItem = null;

  for (var i = 0; i < notes.length; i++) {
    if (notes[i].NoteID === id) {
      noteItem = notes[i];
      break;
    }
  }

  if (!noteItem) throw new Error('Catatan tidak ditemukan: ' + id);

  var now = new Date();
  var newAgenda = {
    TahunAjaran: agendaData.TahunAjaran || noteItem.TahunAjaran || getSetting('TA_AKTIF') || '2026-2027',
    Bulan: agendaData.Bulan || noteItem.Bulan || (new Date().getMonth() + 1),
    Tahun: agendaData.Tahun || noteItem.Tahun || new Date().getFullYear(),
    Unit: agendaData.Unit || noteItem.Unit || 'U001',
    UnitScope: agendaData.UnitScope || 'UNIT',
    TanggalMulai: agendaData.TanggalMulai || null,
    TanggalSelesai: agendaData.TanggalSelesai || null,
    TanggalMentah: null,
    NamaKegiatan: agendaData.NamaKegiatan || noteItem.IsiCatatan || 'Tanpa Nama',
    Kategori: agendaData.Kategori || 'Umum',
    PrioritasDoa: agendaData.PrioritasDoa || 3,
    MasukPokokDoa: agendaData.MasukPokokDoa !== undefined ? agendaData.MasukPokokDoa : true,
    CatatanDoa: agendaData.CatatanDoa || null,
    Status: 'Valid',
    SumberData: 'Tanpa Tanggal',
    CreatedAt: now,
    UpdatedAt: now
  };

  newAgenda.Semester = newAgenda.Bulan >= 7 ? 1 : 2;
  newAgenda.KaldikID = generateId('KAL');
  appendRow('KALDIK_NORMALIZED', newAgenda);

  updateRow('CATATAN_TANPA_TANGGAL', 'NoteID', id, {
    Status: 'Dijadikan Agenda',
    CatatanAdmin: 'Dikonversi ke agenda. KaldikID: ' + newAgenda.KaldikID,
    UpdatedAt: now
  });

  writeChangeLog_('CATATAN_TANPA_TANGGAL', id, 'CONVERT', null, JSON.stringify({ KaldikID: newAgenda.KaldikID }), 'Dikonversi ke KALDIK_NORMALIZED');

  return { NoteID: id, KaldikID: newAgenda.KaldikID, message: 'Catatan berhasil dijadikan agenda' };
}

