/**
 * Duplicate Kaldik
 */
function duplicateKaldik_(id) {
  var allKaldik = readSheet('KALDIK_NORMALIZED');
  var source = allKaldik.find(function(k) { return k.KaldikID === id; });
  if (!source) throw new Error('KaldikID tidak ditemukan: ' + id);
  
  var newData = cloneObject(source);
  newData.KaldikID = generateId('KAL');
  newData.CreatedAt = new Date();
  newData.UpdatedAt = new Date();
  newData.Status = 'Draft';
  
  appendRow('KALDIK_NORMALIZED', newData);
  
  return { KaldikID: newData.KaldikID };
}

/**
 * Pindah tanggal Kaldik
 */
function moveKaldikDate_(id, newStart, newEnd) {
  if (!id) throw new Error('KaldikID diperlukan');
  
  var updateData = { UpdatedAt: new Date() };
  
  if (newStart) {
    var startDate = new Date(newStart);
    updateData.TanggalMulai = startDate;
    updateData.Bulan = startDate.getMonth() + 1;
    updateData.Tahun = startDate.getFullYear();
  }
  
  if (newEnd) {
    updateData.TanggalSelesai = new Date(newEnd);
  }
  
  updateRow('KALDIK_NORMALIZED', 'KaldikID', id, updateData);
  
  return { KaldikID: id };
}

