  if (!id) throw new Error('KaldikID diperlukan');
  
  updateRow('KALDIK_NORMALIZED', 'KaldikID', id, {
    Status: 'Dibatalkan',
    UpdatedAt: new Date()
  });
  
  return { KaldikID: id };
}

