      allTema = allTema.filter(function(t) { return t.TahunAjaran === filters.tahunAjaran; });
    }
    if (filters.semester && filters.semester !== 'all') {
      allTema = allTema.filter(function(t) { return t.Semester == filters.semester; });
    }
    if (filters.bulan && filters.bulan !== 'all') {
      allTema = allTema.filter(function(t) { return t.Bulan == filters.bulan; });
    }
