/**
 * Add tema bulanan baru
 */
function addTema_(data) {
  if (!data.Bulan || !data.Tahun || !data.Unit) {
    throw new Error('Bulan, Tahun, dan Unit wajib diisi');
  }

  // Cek duplikasi: satu tema per unit per bulan per tahun ajaran
  var existing = readSheet('TEMA_BULANAN').filter(function(t) {
    return t.TahunAjaran === data.TahunAjaran &&
           t.Bulan == data.Bulan &&
           t.Tahun == data.Tahun &&
           t.Unit === data.Unit;
  });

  if (existing.length > 0) {
    throw new Error('Tema untuk unit tersebut di bulan/tahun tersebut sudah ada. Silakan edit tema yang sudah ada.');
  }

  var now = new Date();
  var newTema = {
    TemaID: generateId('TMA'),
    TahunAjaran: data.TahunAjaran || getSetting('TA_AKTIF') || '2026-2027',
    Semester: data.Semester || (data.Bulan >= 7 ? 1 : 2),
    Bulan: data.Bulan,
    Tahun: data.Tahun,
    Unit: data.Unit,
    Tema: data.Tema || null,
    Ayat: data.Ayat || null,
    Profil: data.Profil || null,
    Karakter: data.Karakter || null,
    BESTRA: data.BESTRA || null,
    HBE: data.HBE || null,
    HM: data.HM || null,
    CatatanTema: data.CatatanTema || null,
    Status: data.Status || 'Draft',
    UpdatedAt: now
  };

  appendRow('TEMA_BULANAN', newTema);

  writeChangeLog_('TEMA_BULANAN', newTema.TemaID, 'CREATE', null, JSON.stringify({ Tema: newTema.Tema, Unit: newTema.Unit, Bulan: newTema.Bulan }), 'Tema baru dibuat');

  return { TemaID: newTema.TemaID, message: 'Tema berhasil ditambahkan' };
}

