/**
 * Bulk update/create tema bulanan
 * @param {Array<Object>} rows - Array of row objects
 * @return {Object} { status, updated, created }
 */
function bulkUpdateTemaBulanan_(rows) {
  if (!rows || !Array.isArray(rows) || rows.length === 0) {
    throw new Error('Data rows diperlukan dan tidak boleh kosong');
  }

  var updated = 0;
  var created = 0;
  var now = new Date();

  for (var i = 0; i < rows.length; i++) {
    var row = rows[i];
    var temaId = row.TemaID || null;

    // Auto-compute Semester
    var bulan = parseInt(row.Bulan, 10) || 1;
    var semester = bulan >= 7 ? 1 : 2;

    if (temaId) {
      // Update record yang sudah ada
      var updateData = {
        TahunAjaran: row.TahunAjaran || null,
        Semester: semester,
        Bulan: row.Bulan,
        Tahun: row.Tahun,
        Unit: row.Unit,
        Tema: row.Tema || null,
        Ayat: row.Ayat || null,
        Profil: row.Profil || null,
        Karakter: row.Karakter || null,
        BESTRA: row.BESTRA || null,
        HBE: row.HBE || null,
        HM: row.HM || null,
        CatatanTema: row.CatatanTema || null,
        Status: row.Status || 'Draft',
        UpdatedAt: now
      };

      updateRow('TEMA_BULANAN', 'TemaID', temaId, updateData);
      writeChangeLog_('TEMA_BULANAN', temaId, 'BULK_UPDATE', null, JSON.stringify(row), 'Bulk edit tema bulanan');
      updated++;
    } else {
      // Buat record baru dengan auto-generated TemaID
      var newId = 'TEM-' + new Date().getTime() + '-' + Math.floor(Math.random() * 10000);

      var newRow = {
        TemaID: newId,
        TahunAjaran: row.TahunAjaran || getSetting('TA_AKTIF') || '2026-2027',
        Semester: semester,
        Bulan: row.Bulan,
        Tahun: row.Tahun,
        Unit: row.Unit,
        Tema: row.Tema || null,
        Ayat: row.Ayat || null,
        Profil: row.Profil || null,
        Karakter: row.Karakter || null,
        BESTRA: row.BESTRA || null,
        HBE: row.HBE || null,
        HM: row.HM || null,
        CatatanTema: row.CatatanTema || null,
        Status: row.Status || 'Draft',
        UpdatedAt: now
      };

      appendRow('TEMA_BULANAN', newRow);
      writeChangeLog_('TEMA_BULANAN', newId, 'BULK_UPDATE', null, JSON.stringify(row), 'Bulk edit tema bulanan');
      created++;
    }
  }

  return { status: 'success', updated: updated, created: created };
}

/**
 * Utils.gs — Helper Functions
 * ID Generator, Date Helpers, JSON Response Builder
 */

/**
 * Generate unique ID dengan prefix
 * Format: {PREFIX}-{timestamp}
 */
function generateId(prefix) {
  var timestamp = new Date().getTime();
  return prefix.toUpperCase() + '-' + timestamp;
}

/**
 * Build JSON response standar
 */
function buildJsonResponse(status, data, message) {
  var response = {
    status: status,
    data: data || null,
    message: message || (status === 'success' ? 'OK' : 'Error'),
    timestamp: new Date().toISOString()
  };
  return ContentService
    .createTextOutput(JSON.stringify(response))
    .setMimeType(ContentService.MimeType.JSON);
}

/**
 * Format tanggal ke string YYYY-MM-DD
 */
function formatDate(date) {
  if (!date) return null;
  var d = new Date(date);
  var yyyy = d.getFullYear();
  var mm = ('0' + (d.getMonth() + 1)).slice(-2);
  var dd = ('0' + d.getDate()).slice(-2);
  return yyyy + '-' + mm + '-' + dd;
}

/**
 * Format tanggal ke string readable (Indonesia)
 */
function formatDateReadable(date) {
  if (!date) return '';
  var d = new Date(date);
  var bulan = ['Januari', 'Februari', 'Maret', 'April', 'Mei', 'Juni',
               'Juli', 'Agustus', 'September', 'Oktober', 'November', 'Desember'];
  return d.getDate() + ' ' + bulan[d.getMonth()] + ' ' + d.getFullYear();
}

/**
 * Parse string tanggal ke Date object
 */
function parseDate(dateStr) {
  if (!dateStr) return null;
  // Handle YYYY-MM-DD
  var parts = dateStr.split('-');
  if (parts.length === 3) {
    return new Date(parseInt(parts[0]), parseInt(parts[1]) - 1, parseInt(parts[2]));
  }
  // Handle DD/MM/YYYY
  parts = dateStr.split('/');
  if (parts.length === 3) {
    return new Date(parseInt(parts[2]), parseInt(parts[1]) - 1, parseInt(parts[0]));
  }
  return new Date(dateStr);
}

/**
 * Dapatkan nama hari dalam Bahasa Indonesia
 */
function getDayName(date) {
  if (!date) return '';
  var days = ['Minggu', 'Senin', 'Selasa', 'Rabu', 'Kamis', 'Jumat', 'Sabtu'];
  return days[new Date(date).getDay()];
}

/**
 * Dapatkan nama bulan dalam Bahasa Indonesia
 */
function getMonthName(monthIndex) {
  var months = ['', 'Januari', 'Februari', 'Maret', 'April', 'Mei', 'Juni',
                'Juli', 'Agustus', 'September', 'Oktober', 'November', 'Desember'];
  return months[monthIndex] || '';
}

/**
 * Dapatkan jumlah hari dalam bulan
 */
function getDaysInMonth(month, year) {
  return new Date(year, month, 0).getDate();
}

/**
 * Dapatkan semester dari bulan
 */
function getSemester(month) {
  return month >= 7 ? 1 : 2;
}

/**
 * Escape HTML (keamanan)
 */
function escapeHtml(str) {
  if (!str) return '';
  return str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');
}

/**
 * Deep clone object sederhana
 */
function cloneObject(obj) {
  return JSON.parse(JSON.stringify(obj));
}

/**
 * Convert row array ke object dengan header
 */
function rowToObject(headers, row) {
  var obj = {};
  for (var i = 0; i < headers.length; i++) {
    obj[headers[i]] = row[i] !== undefined ? row[i] : null;
  }
  return obj;
}

/**
 * Convert object ke row array dengan header
 */
function objectToRow(headers, obj) {
  var row = [];
  for (var i = 0; i < headers.length; i++) {
    row.push(obj[headers[i]] !== undefined ? obj[headers[i]] : null);
  }
  return row;
}

/**
 * Sanitize data for client serialization
 * Converts Date objects to ISO strings (Google Apps Script can't serialize Dates via google.script.run)
 */
function sanitizeForClient_(data) {
  if (data === null || data === undefined) return data;
  if (data instanceof Date) return data.toISOString();
  if (Array.isArray(data)) return data.map(sanitizeForClient_);
  if (typeof data === 'object') {
    var clean = {};
    for (var key in data) {
      if (data.hasOwnProperty(key)) {
        clean[key] = sanitizeForClient_(data[key]);
      }
    }
    return clean;
  }
  return data;
}

/**
 * Filter array of objects dengan kondisi
 */
function filterObjects(array, filters) {
  return array.filter(function(item) {
    for (var key in filters) {
      if (filters[key] === undefined || filters[key] === null || filters[key] === '') continue;
      if (key === '_search') {
        // Pencarian text di semua field
        var found = false;
        var searchLower = filters[key].toLowerCase();
        for (var k in item) {
          if (item[k] && String(item[k]).toLowerCase().indexOf(searchLower) > -1) {
            found = true;
            break;
          }
        }
        if (!found) return false;
      } else if (item[key] != filters[key]) {
        return false;
      }
    }
    return true;
  });
}

