/**
 * Global unit code mapping.
 * Maps all known unit codes (U001-U007, abbreviations, full names) to display names.
 */
var UNIT_CODE_MAP = {
  'U001': 'Universal',
  'U002': 'TK',
  'U003': 'SD',
  'U004': 'SMP',
  'U005': 'Manajemen',
  'U006': 'TBI',
  'U007': 'RTS',

  'UNI': 'Universal',
  'UNIVERSAL': 'Universal',
  'SEMUA': 'Universal',
  'SEMUA UNIT': 'Universal',

  'TK': 'TK',
  'KB-TK': 'TK',
  'KBTK': 'TK',

  'SD': 'SD',
  'SMP': 'SMP',
  'TBI': 'TBI',
  'RTS': 'RTS',

  'MNG': 'Manajemen',
  'MANAJEMEN': 'Manajemen',
  'MANAGEMENT': 'Manajemen'
};

/**
 * Normalize any unit value to its canonical display name.
 * "U002" → "TK", "universal" → "Universal", "mng" → "Manajemen", etc.
 * Unknown values are returned as-is (trimmed).
 * @param {string} unitValue
 * @return {string}
 */
function normalizeUnit(unitValue) {
  var raw = String(unitValue || '').trim();
  var key = raw.toUpperCase();
  return UNIT_CODE_MAP[key] || raw;
}

/**
 * Normalize unit value to a CSS-safe class name.
 * "U002" → "tk", "Manajemen" → "manajemen", "SMP" → "smp"
 * @param {string} unitValue
 * @return {string}
 */
function normalizeUnitClass(unitValue) {
  return normalizeUnit(unitValue)
    .toLowerCase()
    .replace(/\s+/g, '-');
}

