/**
 * Get cached JSON value from Script Cache.
 * @param {string} key
 * @return {*} Parsed JSON or null if not found.
 */
function getCacheJson(key) {
  try {
    var cache = CacheService.getScriptCache();
    var val = cache.get(key);
    return val ? JSON.parse(val) : null;
  } catch (e) {
    return null;
  }
}

/**
 * Store JSON value in Script Cache.
 * @param {string} key
 * @param {*} data - Will be JSON-stringified.
 * @param {number} seconds - TTL in seconds (default 300 = 5 menit).
 */
function setCacheJson(key, data, seconds) {
  try {
    CacheService.getScriptCache().put(key, JSON.stringify(data), seconds || 300);
  } catch (e) {
    // Silent fail — cache is optional
  }
}
